INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('a0135659-c89e-456f-98da-3c6d739a3ac2', 'dd10638e-9453-4373-a946-253dc336c933', 'OA1', 'conocimiento', 'Ciencias de la Vida', 'Reconocer y observar, por medio de la exploración, que los seres vivos crecen, responden a estímulos del medio, se reproducen y necesitan agua, alimento y aire para vivir, comparándolos con las cosas no vivas.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('80172f4d-3925-4e58-b8ef-55d682824019', 'dd10638e-9453-4373-a946-253dc336c933', 'OA2', 'conocimiento', 'Ciencias de la Vida', 'Observar y comparar animales de acuerdo a características como tamaño, cubierta corporal, estructuras de desplazamiento y hábitat, entre otras.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('12eaf65c-8c82-4a8b-9d0e-c9719dfd8069', 'dd10638e-9453-4373-a946-253dc336c933', 'OA3', 'conocimiento', 'Ciencias de la Vida', 'Observar e identificar, por medio de la exploración, las estructuras principales de las plantas: hojas, flores, tallos y raíces.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('584198a9-0235-4375-a13f-8f08de309cf9', 'dd10638e-9453-4373-a946-253dc336c933', 'OA4', 'conocimiento', 'Ciencias de la Vida', 'Observar y clasificar semillas, frutos, flores y tallos a partir de criterios como tamaño, forma, textura y color, entre otros.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('6a81c1d6-8150-4036-b46e-6402aa988a7b', 'dd10638e-9453-4373-a946-253dc336c933', 'OA5', 'conocimiento', 'Ciencias de la Vida', 'Reconocer y comparar diversas plantas y animales de nuestro país, considerando las características observables y proponiendo medidas para su cuidado.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('8958d626-defb-4dad-9375-d6717992d4f3', 'dd10638e-9453-4373-a946-253dc336c933', 'OA6', 'conocimiento', 'Ciencias de la Vida', 'Identificar y describir la ubicación y la función de los sentidos, proponiendo medidas para protegerlos y para prevenir situaciones de riesgo.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('8bebc3bc-203f-4f5a-8ed9-4de180d8a0a0', 'dd10638e-9453-4373-a946-253dc336c933', 'OA7', 'conocimiento', 'Ciencias de la Vida', 'Describir, dar ejemplos y practicar hábitos de vida saludable para mantener el cuerpo sano y prevenir enfermedades (actividad física, aseo del cuerpo, lavado de alimentos y alimentación saludable, entre otros).') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('bd139820-281b-49c9-b2ef-68ba003f02c1', 'dd10638e-9453-4373-a946-253dc336c933', 'OA8', 'conocimiento', 'Ciencias de la Vida', 'Explorar y describir los diferentes tipos de materiales en diversos objetos, clasificándolos según sus propiedades (goma-flexible, plástico-impermeable) e identificando su uso en la vida cotidiana.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('f21993b1-a8f1-4170-becb-810ac91c66bc', 'dd10638e-9453-4373-a946-253dc336c933', 'OA9', 'conocimiento', 'Ciencias Físicas y Químicas', 'Observar y describir los cambios que se producen en los materiales al aplicarles fuerza, luz, calor y agua. 10 Diseñar instrumentos tecnológicos simples, considerando diversos materiales y sus propiedades para resolver problemas cotidianos. istrar el ciclo diario y las diferencias entre el día y la noche, a servación del Sol, la Luna, las estrellas y la luminosidad del cielo, entre otras, y sus efectos en los seres vivos y el ambiente. unicar los cambios del ciclo de las estaciones y sus efectos en los seres vivos y el ambiente.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('60593513-5c2f-4efa-b9e0-bf36fbf611ca', 'dd10638e-9453-4373-a946-253dc336c933', 'OA_a', 'habilidad', 'Ciencias de la Vida', 'Explorar, observar y formular inferencias y predicciones, en forma guiada, sobre objetos y eventos del entorno.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
