INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('6f66a753-d382-4ed5-b7e8-3d618a65d408', 'dd10638e-9453-4373-a946-253dc336c933', 'OA_c', 'habilidad', 'Habilidades: Experimentar', 'Observar, medir y registrar los datos cuidadosamente, utilizando unidades no estandarizadas.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('c439a106-2ace-4965-852a-a8b708114f30', 'dd10638e-9453-4373-a946-253dc336c933', 'OA_d', 'habilidad', 'Habilidades: Experimentar', 'Seguir las instrucciones para utilizar los materiales y los instrumentos en forma segura.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
