INSERT INTO curriculum_grades (id, subject_id, grado, label, total_objetivos) VALUES ('47b20544-a2e9-4f25-8029-f93c40741b5b', 'c501f8cc-ddd6-42df-92cf-c77bbfa2ded6', '2', '2° Básico', 15) ON CONFLICT (id) DO UPDATE SET subject_id = EXCLUDED.subject_id, grado = EXCLUDED.grado, label = EXCLUDED.label, total_objetivos = EXCLUDED.total_objetivos;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('2f76fe73-eaa5-4d70-97a0-cb3eafef8eb3', '47b20544-a2e9-4f25-8029-f93c40741b5b', 'OA1', 'conocimiento', 'Ciencias de la Vida', 'Observar, describir y clasificar los vertebrados en mamíferos, aves, reptiles, anfibios y peces, a partir de características como cubierta corporal, presencia de mamas y estructuras para la respiración, entre otras.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('53e0a017-2449-46cf-b874-b908ac88ff45', '47b20544-a2e9-4f25-8029-f93c40741b5b', 'OA2', 'conocimiento', 'Ciencias de la Vida', 'Observar, describir y clasificar, por medio de la exploración, las características de los animales sin columna vertebral, como insectos, arácnidos, crustáceos, entre otros, y compararlos con los vertebrados.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('70848fa3-4ee8-4ad6-8e78-e6332e05a8c0', '47b20544-a2e9-4f25-8029-f93c40741b5b', 'OA3', 'conocimiento', 'Ciencias de la Vida', 'Observar y comparar las características de las etapas del ciclo de vida de distintos animales (mamíferos, aves, insectos y anfibios), relacionándolas con su hábitat.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('01adf0e7-fe9a-44d7-a34d-47321b655495', '47b20544-a2e9-4f25-8029-f93c40741b5b', 'OA4', 'conocimiento', 'Ciencias de la Vida', 'Observar y comparar las características de distintos hábitat, identificando la luminosidad, la humedad y la temperatura necesarias para la supervivencia de los animales que habitan en él.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('7e559ada-9f30-4420-828e-968b8adfde72', '47b20544-a2e9-4f25-8029-f93c40741b5b', 'OA5', 'conocimiento', 'Ciencias de la Vida', 'Observar e identificar algunos animales nativos que se encuentran en peligro de extinción, así como el deterioro de su hábitat, proponiendo medidas para protegerlos.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('b692f5e2-d207-4b33-9310-ba83f9809916', '47b20544-a2e9-4f25-8029-f93c40741b5b', 'OA6', 'conocimiento', 'Ciencias de la Vida', 'Identificar y comunicar los efectos de la actividad humana sobre los animales y su hábitat.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('5e686e3c-686a-41a1-a768-2e082bd3a5d2', '47b20544-a2e9-4f25-8029-f93c40741b5b', 'OA7', 'conocimiento', 'Ciencias de la Vida', 'Identificar la ubicación y explicar la función de algunas partes del cuerpo que son fundamentales para vivir: corazón, pulmones, estómago, esqueleto y músculos.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('c6d67288-2413-457b-834b-9612745779a3', '47b20544-a2e9-4f25-8029-f93c40741b5b', 'OA8', 'conocimiento', 'Ciencias de la Vida', 'Explicar la importancia de la actividad física para el desarrollo de los músculos y el fortalecimiento del corazón, proponiendo formas de ejercitarla e incorporarla en sus hábitos diarios.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('3989241b-122f-4ba2-b97d-ae63bc374686', '47b20544-a2e9-4f25-8029-f93c40741b5b', 'OA9', 'conocimiento', 'Ciencias de la Vida', 'Observar y describir, por medio de la investigación experimental, algunas características del agua, como: 10 Identificar y comparar, por medio de la exploración, los estados sólido, líquido y gaseoso del agua. 11 Describir el ciclo del agua en la naturaleza, reconociendo que el agua es un recurso preciado y proponiendo acciones cotidianas para su cuidado. otras, y sus cambios a lo largo del año. do algunos instrumentos tecnológicos útiles para su localidad, como termómetro, pluviómetro o veleta. 14 Describir la relación de los cambios del tiempo atmosférico con las estaciones del año y sus efectos sobre los seres vivos y el ambiente.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
