INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('5ade6d49-2abb-4607-adbd-8f2ed4c14bd9', '64da1f58-a7fb-4679-89ba-bc5f4e1c4830', 'OA1', 'conocimiento', 'Ciencias de la Vida', 'Observar y describir, por medio de la investigación experimental, las necesidades de las plantas y su relación con la raíz, el tallo y las hojas.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('c8a6ee4d-df26-4a7b-91cc-0006bdaceea3', '64da1f58-a7fb-4679-89ba-bc5f4e1c4830', 'OA2', 'conocimiento', 'Ciencias de la Vida', 'Observar, registrar e identificar variadas plantas de nuestro país, incluyendo vegetales autóctonos y cultivos principales a nivel nacional y regional.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('f002341b-419c-4591-9ac8-73ffe7f94391', '64da1f58-a7fb-4679-89ba-bc5f4e1c4830', 'OA3', 'conocimiento', 'Ciencias de la Vida', 'Observar y describir algunos cambios de las plantas con flor durante su ciclo de vida (germinación, crecimiento, reproducción, formación de la flor y del fruto), reconociendo la importancia de la polinización y de la dispersión de la semilla.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('48e2e1ba-928f-48fe-8edc-ba8c74dd388a', '64da1f58-a7fb-4679-89ba-bc5f4e1c4830', 'OA4', 'conocimiento', 'Ciencias de la Vida', 'Describir la importancia de las plantas para los seres vivos, el ser humano y el medioambiente (por ejemplo: alimentación, aire para respirar, productos derivados, ornamentación, uso medicinal), proponiendo y comunicando medidas de cuidado.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('3875dc22-c185-49ca-a4be-756cee30cfe2', '64da1f58-a7fb-4679-89ba-bc5f4e1c4830', 'OA5', 'conocimiento', 'Ciencias de la Vida', 'Explicar la importancia de usar adecuadamente los recursos, proponiendo acciones y construyendo instrumentos tecnológicos para reutilizarlos, reducirlos y reciclarlos en la casa y en la escuela.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('099dc8ce-b640-4728-9a16-51e455045fa8', '64da1f58-a7fb-4679-89ba-bc5f4e1c4830', 'OA6', 'conocimiento', 'Ciencias de la Vida', 'Clasificar los alimentos, distinguiendo sus efectos sobre la salud, y proponer hábitos alimenticios saludables.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('638a639d-b8b7-4d5f-8d97-1a2ef66bd8dd', '64da1f58-a7fb-4679-89ba-bc5f4e1c4830', 'OA7', 'conocimiento', 'Ciencias de la Vida', 'Proponer, comunicar y ejercitar buenas prácticas de higiene en la manipulación de alimentos para prevenir enfermedades.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('42c1bbe2-e0b7-4aaa-8927-53b62e0bc924', '64da1f58-a7fb-4679-89ba-bc5f4e1c4830', 'OA8', 'conocimiento', 'Ciencias de la Vida', 'Distinguir fuentes naturales y artificiales de luz, como el Sol, las ampolletas y el fuego, entre otras.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('67fcfa07-0afe-41f7-b61a-0b8046578c0f', '64da1f58-a7fb-4679-89ba-bc5f4e1c4830', 'OA9', 'conocimiento', 'Ciencias Físicas y Químicas', 'Investigar experimentalmente y explicar algunas características de la luz; por ejemplo: viaja en línea recta, se refleja, puede ser separada en colores. 10 Investigar experimentalmente y explicar las características del sonido; por ejemplo: viaja en todas las direcciones, se absorbe o se refleja, se transmite por medio de distintos materiales, tiene tono e intensidad. aracterísticas de algunos de los componentes del Sistema Solar lunas, cometas y asteroides) en relación con su tamaño, localización, apariencia y distancia relativa a la Tierra, entre otros. edio de modelos, los movimientos de rotación y traslación, considerando sus efectos en la Tierra. 13 Diseñar y construir modelos tecnológicos para explicar eventos del Sistema Solar, como la sucesión de las fases de la Luna y los eclipses de Luna y de Sol, entre otros.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('6cbbc665-c411-4c81-b156-8de188386104', '64da1f58-a7fb-4679-89ba-bc5f4e1c4830', 'OA_a', 'habilidad', 'Ciencias de la Vida', 'Plantear preguntas y formular predicciones, en forma guiada, sobre objetos y eventos del entorno.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('6ff329e0-dd83-4be1-8032-f1c405bb51aa', '64da1f58-a7fb-4679-89ba-bc5f4e1c4830', 'OA_b', 'habilidad', 'Habilidades: Planificar y conducir una investigación', 'Planificar y llevar a cabo investigaciones guiadas experimentales y no experimentales: ú obteniendo información para responder a preguntas dadas a partir de diverú sas fuentes sobre la base de una pregunta formulada por ellos u otros') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objective_items (objective_id, orden, descripcion) VALUES ('6ff329e0-dd83-4be1-8032-f1c405bb51aa', 1, 'estableciendo un procedimiento previo simple para responderla') ON CONFLICT (objective_id, orden) DO UPDATE SET descripcion = EXCLUDED.descripcion;
