INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('aafcb391-6061-41f8-a7dd-e743af166da5', '64da1f58-a7fb-4679-89ba-bc5f4e1c4830', 'OA_c', 'habilidad', 'Habilidades: Planificar y conducir una investigación', 'Observar, medir, registrar y comparar datos en forma precisa con instrumentos de medición, utilizando tablas, gráficos y TIC cuando corresponda.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('057bcbbb-53ac-4fac-a4a2-aeafbf08938f', '64da1f58-a7fb-4679-89ba-bc5f4e1c4830', 'OA_d', 'habilidad', 'Habilidades: Planificar y conducir una investigación', 'Usar materiales e instrumentos en forma segura y autónoma, como reglas, termómetros y vasos graduados, entre otros, para hacer observaciones y mediciones.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('1495d30e-4a32-4fa6-84fd-b5a362a9a519', '64da1f58-a7fb-4679-89ba-bc5f4e1c4830', 'OA_e', 'habilidad', 'Habilidades: Analizar la evidencia y comunicar', 'Comparar sus predicciones con la pregunta inicial, utilizando sus observaciones como evidencia para apoyar ideas.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('b1b06409-923c-49b5-aacd-69ed483efa0f', '64da1f58-a7fb-4679-89ba-bc5f4e1c4830', 'OA_f', 'habilidad', 'Habilidades: Analizar la evidencia y comunicar', 'Comunicar ideas, explicaciones, observaciones y mediciones, utilizando diagramas, modelos físicos, informes y presentaciones, usando TIC.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_grades (id, subject_id, grado, label, total_objetivos) VALUES ('05dce6d2-6102-473d-874d-afb5086f3ddc', 'c501f8cc-ddd6-42df-92cf-c77bbfa2ded6', '4', '4° Básico', 17) ON CONFLICT (id) DO UPDATE SET subject_id = EXCLUDED.subject_id, grado = EXCLUDED.grado, label = EXCLUDED.label, total_objetivos = EXCLUDED.total_objetivos;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('66665dc2-75a9-4a10-942e-c64e60b31952', '05dce6d2-6102-473d-874d-afb5086f3ddc', 'OA1', 'conocimiento', 'Ciencias de la Vida', 'Reconocer, por medio de la exploración, que un ecosistema está compuesto por elementos vivos (animales, plantas, etc.) y no vivos (piedras, agua, tierra, etc.) que interactúan entre sí.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('5b929aa9-1047-4116-ba33-f1eda9fed028', '05dce6d2-6102-473d-874d-afb5086f3ddc', 'OA2', 'conocimiento', 'Ciencias de la Vida', 'Observar y comparar adaptaciones de plantas y animales para sobrevivir en los ecosistemas en relación con su estructura y conducta; por ejemplo: cubierta corporal, camuflaje, tipo de hojas, hibernación, entre otras.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('87cb8162-d21b-42c6-8685-d39bb3d2d4f7', '05dce6d2-6102-473d-874d-afb5086f3ddc', 'OA3', 'conocimiento', 'Ciencias de la Vida', 'Dar ejemplos de cadenas alimentarias, identificando la función de los organismos productores, consumidores y descomponedores, en diferentes ecosistemas de Chile.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('00d566f4-b83c-46bf-95fb-d33641565ee2', '05dce6d2-6102-473d-874d-afb5086f3ddc', 'OA4', 'conocimiento', 'Ciencias de la Vida', 'Analizar los efectos de la actividad humana en ecosistemas de Chile, proponiendo medidas para protegerlos (parques nacionales y vedas, entre otras).') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('d55cbeaf-e80a-4808-9f2f-82b8eea76858', '05dce6d2-6102-473d-874d-afb5086f3ddc', 'OA5', 'conocimiento', 'Ciencias de la Vida', 'Identificar y describir, usando modelos, estructuras del sistema esquelético y algunas de sus funciones, como protección (costillas y cráneo), soporte (vértebras y columna vertebral) y movimiento (pelvis y fémur).') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('8769c47f-326a-4735-a0b5-632395cc688c', '05dce6d2-6102-473d-874d-afb5086f3ddc', 'OA6', 'conocimiento', 'Ciencias de la Vida', 'Explicar, con apoyo de modelos, el movimiento del cuerpo, considerando la acción coordinada de músculos, huesos, tendones y articulación (ejemplo: brazo y pierna), y describir los beneficios de la actividad física para el sistema músculo-esquelético.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('954b7db4-bd45-4fa4-88f8-8eac1f499078', '05dce6d2-6102-473d-874d-afb5086f3ddc', 'OA7', 'conocimiento', 'Ciencias de la Vida', 'Identificar estructuras del sistema nervioso y describir algunas de sus funciones, como conducción de información (médula espinal y nervios) y elaboración y control (cerebro).') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('692ce826-5e49-4350-b769-c8338b2c9ea6', '05dce6d2-6102-473d-874d-afb5086f3ddc', 'OA8', 'conocimiento', 'Ciencias de la Vida', 'Investigar en diversas fuentes y comunicar los efectos que produce el consumo excesivo de alcohol en la salud humana (como descoordinación, confusión y lentitud, entre otras).') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('f33e9d02-ddda-4445-af43-3d7b7915d000', '05dce6d2-6102-473d-874d-afb5086f3ddc', 'OA9', 'conocimiento', 'Ciencias de la Vida', 'Demostrar, por medio de la investigación experimental, que la materia tiene masa y ocupa espacio, usando materiales del entorno. parar los tres estados de la materia (sólido, líquido y gaseoso) en relación con criterios como la capacidad de fluir y cambiar de forma y volumen, entre otros. 11 Medir la masa, el volumen y la temperatura de la materia (en estados sólido, líquido y gaseoso), utilizando instrumentos y unidades de medida apropiados. 12 Demostrar, por medio de la investigación experimental, los efectos de la aplicación de fuerzas sobre objetos, considerando cambios en la forma, la rapidez y la dirección del movimiento, entre otros. 13 Identificar, por medio de la investigación experimental, diferentes tipos de fuerzas y sus efectos en situaciones concretas: úfuerza de roce (arrastrando objetos) úpeso (fuerza de gravedad) úfuerza magnética (en imanes) 14 Diseñar y construir objetos tecnológicos que usen la fuerza, para resolver problemas cotidianos. medio de modelos, que la Tierra tiene una estructura de capas y núcleo) con características distintivas en cuanto a su composición, rigidez y temperatura. mbios de la superficie de la Tierra a partir de la interacción de sus capas y los movimientos de las placas tectónicas (sismos, tsunamis y erupciones volcánicas). 17 Proponer medidas de prevención y seguridad ante riesgos naturales en la escuela, la calle y el hogar, para desarrollar una cultura preventiva.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('122c6f00-04bb-4122-8cc7-bf03fd33bbaa', '05dce6d2-6102-473d-874d-afb5086f3ddc', 'OA_a', 'habilidad', 'Ciencias Físicas y Químicas', 'Seleccionar preguntas significativas que se puedan investigar.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('f253c925-bb9b-44a6-8e32-08c1f84bd6a3', '05dce6d2-6102-473d-874d-afb5086f3ddc', 'OA_b', 'habilidad', 'Habilidades: Observar y preguntar', 'Formular predicciones de resultados de una investigación, de forma autónoma, fundamentándolas.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
