INSERT INTO curriculum_objective_items (objective_id, orden, descripcion) VALUES ('12f50928-6ede-477c-8bae-edcf67953230', 3, 'obteniendo información sobre el tema en estudio a partir de diversas fuentes y aplicando estrategias para organizar y comunicar la información.') ON CONFLICT (objective_id, orden) DO UPDATE SET descripcion = EXCLUDED.descripcion;
