INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('e82f65f8-06a7-40d7-9f64-07a343088046', '05dce6d2-6102-473d-874d-afb5086f3ddc', 'OA_e', 'habilidad', 'Habilidades: Planificar y conducir una investigación', 'Seleccionar materiales e instrumentos, usándolos de manera segura y adecuada e identificando los riesgos potenciales.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
