INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('8289f6b7-8c3f-43c5-bf8a-c4646d56dec2', '05dce6d2-6102-473d-874d-afb5086f3ddc', 'OA_h', 'habilidad', 'Habilidades: Analizar la evidencia y comunicar', 'Reflexionar y comunicar fortalezas y debilidades en la planificación y el desarrollo de sus investigaciones, en forma oral y escrita.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_grades (id, subject_id, grado, label, total_objetivos) VALUES ('7a9d03b8-8d95-4589-a898-92cabce2324e', 'c501f8cc-ddd6-42df-92cf-c77bbfa2ded6', '5', '5° Básico', 16) ON CONFLICT (id) DO UPDATE SET subject_id = EXCLUDED.subject_id, grado = EXCLUDED.grado, label = EXCLUDED.label, total_objetivos = EXCLUDED.total_objetivos;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('f81c9cf7-65a8-43d1-8a40-d363699075e4', '7a9d03b8-8d95-4589-a898-92cabce2324e', 'OA1', 'conocimiento', 'Ciencias de la Vida', 'Reconocer y explicar que los seres vivos están formados por una o más células y que estas se organizan en tejidos, órganos y sistemas.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('fae593d2-793c-4bd3-9aca-98fa2df46fcb', '7a9d03b8-8d95-4589-a898-92cabce2324e', 'OA2', 'conocimiento', 'Ciencias de la Vida', 'Identificar y describir, por medio de modelos, las estructuras básicas del sistema digestivo (boca, esófago, estómago, hígado, intestino delgado, intestino grueso, recto y ano) y sus funciones en la digestión, la absorción de alimentos y la eliminación de desechos.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('65d5148c-6d0f-4ce9-b2ad-93765a15bb18', '7a9d03b8-8d95-4589-a898-92cabce2324e', 'OA3', 'conocimiento', 'Ciencias de la Vida', 'Explicar, por medio de modelos, la respiración (inspiración-espiración-intercambio de oxígeno y dióxido de carbono), identificando las estructuras básicas del sistema respiratorio (nariz, tráquea, bronquios, alvéolos, pulmones).') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('1fb95742-b547-4701-b864-759271242ff6', '7a9d03b8-8d95-4589-a898-92cabce2324e', 'OA4', 'conocimiento', 'Ciencias de la Vida', 'Explicar la función de transporte del sistema circulatorio (sustancias alimenticias, oxígeno y dióxido de carbono), identificando sus estructuras básicas (corazón, vasos sanguíneos y sangre).') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('b27336fa-4627-4cad-be8f-645d5eb7c3a7', '7a9d03b8-8d95-4589-a898-92cabce2324e', 'OA5', 'conocimiento', 'Ciencias de la Vida', 'Analizar el consumo de alimento diario (variedad, tamaño y frecuencia de porciones), reconociendo los alimentos para el crecimiento, la reparación, el desarrollo y el movimiento del cuerpo.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('b5b4fa73-a452-4fc2-a0ca-e459639bb2bc', '7a9d03b8-8d95-4589-a898-92cabce2324e', 'OA6', 'conocimiento', 'Ciencias de la Vida', 'Investigar en diversas fuentes y comunicar los efectos nocivos que produce el cigarrillo (humo del tabaco) en los sistemas respiratorio y circulatorio.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('07d3fda2-c041-4464-9f41-3f169ed7ef9f', '7a9d03b8-8d95-4589-a898-92cabce2324e', 'OA7', 'conocimiento', 'Ciencias de la Vida', 'Investigar e identificar algunos microorganismos beneficiosos y dañinos para la salud (bacterias, virus y hongos), y proponer medidas de cuidado e higiene del cuerpo.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('d2ea4d8a-1c33-48ab-8a26-eda8dd6283d6', '7a9d03b8-8d95-4589-a898-92cabce2324e', 'OA8', 'conocimiento', 'Ciencias de la Vida', 'Reconocer los cambios que experimenta la energía eléctrica al pasar de una forma a otra (eléctrica a calórica, sonora, lumínica, etc.) e investigar los principales aportes de científicos en su estudio a lo largo del tiempo.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('11efc2f2-a977-4518-9f96-4b7ae77afd61', '7a9d03b8-8d95-4589-a898-92cabce2324e', 'OA9', 'conocimiento', 'Ciencias Físicas y Químicas', 'Construir un circuito eléctrico simple (cable, ampolleta, interruptor y pila), usarlo para resolver problemas cotidianos y explicar su funcionamiento. 10 Observar y distinguir, por medio de la investigación experimental, los materiales conductores (cobre y aluminio) y aisladores (plásticos y goma) de electricidad, relacionándolos con la manipulación segura de artefactos tecnológicos y circuitos eléctricos domiciliarios. 11 Explicar la importancia de la energía eléctrica en la vida cotidiana y proponer medidas para promover su ahorro y su uso responsable. istribución del agua dulce y salada en la Tierra, considerando ares, ríos y lagos, aguas subterráneas, nubes, vapor de agua, etc., y comparar sus volúmenes, reconociendo la escasez relativa de agua 13 Analizar y describir las características de los océanos y lagos: úvariación de temperatura, luminosidad y presión en relación con la profundidad údiversidad de flora y fauna úmovimiento de las aguas, como olas, mareas, corrientes (El Niño y Humboldt) 14 Investigar y explicar efectos positivos y negativos de la actividad humana en océanos, lagos, ríos, glaciares, entre otros, proponiendo acciones de protección de las reservas hídricas en Chile y comunicando sus resultados.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('2efe6c1e-9a6e-45b0-977a-1f336ae193dc', '7a9d03b8-8d95-4589-a898-92cabce2324e', 'OA_a', 'habilidad', 'Ciencias de la Vida', 'Identificar preguntas simples de carácter científico, que permitan realizar una investigación y formular una predicción de los resultados de ésta, fundamentándolos.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('bda00ab0-4d70-4a19-b7a0-abec426cb906', '7a9d03b8-8d95-4589-a898-92cabce2324e', 'OA_b', 'habilidad', 'Habilidades: Planificar y conducir una investigación', 'Planificar y llevar a cabo investigaciones experimentales y no experimentales de manera independiente:') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objective_items (objective_id, orden, descripcion) VALUES ('bda00ab0-4d70-4a19-b7a0-abec426cb906', 1, 'sobre la base de una pregunta formulada por ellos u otros ú identificando variables que se mantienen, que cambian y que dan resultado en una investigación experimental') ON CONFLICT (objective_id, orden) DO UPDATE SET descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objective_items (objective_id, orden, descripcion) VALUES ('bda00ab0-4d70-4a19-b7a0-abec426cb906', 2, 'trabajando de forma individual o colaborativa') ON CONFLICT (objective_id, orden) DO UPDATE SET descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objective_items (objective_id, orden, descripcion) VALUES ('bda00ab0-4d70-4a19-b7a0-abec426cb906', 3, 'obteniendo información sobre el tema en estudio a partir de diversas fuentes y aplicando estrategias para organizar y comunicar la información') ON CONFLICT (objective_id, orden) DO UPDATE SET descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('339bf6e0-4401-40de-b4c7-16af525f8b9f', '7a9d03b8-8d95-4589-a898-92cabce2324e', 'OA_c', 'habilidad', 'Habilidades: Planificar y conducir una investigación', 'Medir y registrar datos en forma precisa con instrumentos de medición, especificando las unidades de medida, identificando patrones simples y usando las TIC cuando corresponda.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('d0c336c5-b60e-499b-9064-3333a3d87028', '7a9d03b8-8d95-4589-a898-92cabce2324e', 'OA_d', 'habilidad', 'Habilidades: Planificar y conducir una investigación', 'Seleccionar materiales e instrumentos, usándolos de manera segura y adecuada e identificando los riesgos potenciales.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('d9fd7bac-b108-4a6c-851a-ebcb568ccd50', '7a9d03b8-8d95-4589-a898-92cabce2324e', 'OA_e', 'habilidad', 'Habilidades: Analizar la evidencia y comunicar', 'Formular explicaciones razonables y conclusiones, a partir de la comparación entre los resultados obtenidos en la experimentación y sus predicciones.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('3c8e56e6-2a2d-4f17-a79c-4d6c59006656', '7a9d03b8-8d95-4589-a898-92cabce2324e', 'OA_f', 'habilidad', 'Habilidades: Analizar la evidencia y comunicar', 'Comunicar y representar evidencias y conclusiones de una investigación, utilizando modelos, presentaciones, TIC e informes, entre otros.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('f4375704-7bc0-4621-877d-5de8df7727f9', '7a9d03b8-8d95-4589-a898-92cabce2324e', 'OA_g', 'habilidad', 'Habilidades: Analizar la evidencia y comunicar', 'Reflexionar, comunicar y proponer mejoras en sus investigaciones, identificando errores y aspectos a mejorar en sus procedimientos.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_grades (id, subject_id, grado, label, total_objetivos) VALUES ('d755f7e0-ed6e-46e9-9be1-eaab302eb1fb', 'c501f8cc-ddd6-42df-92cf-c77bbfa2ded6', '6', '6° Básico', 9) ON CONFLICT (id) DO UPDATE SET subject_id = EXCLUDED.subject_id, grado = EXCLUDED.grado, label = EXCLUDED.label, total_objetivos = EXCLUDED.total_objetivos;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('ea733e72-6236-4907-93a0-4163b797d580', 'd755f7e0-ed6e-46e9-9be1-eaab302eb1fb', 'OA1', 'conocimiento', 'Ciencias de la Vida', 'Explicar, a partir de una investigación experimental, los requerimientos de agua, dióxido de carbono y energía lumínica para la producción de azúcar y la liberación de oxígeno en la fotosíntesis, comunicando sus resultados y los aportes de científicos en este campo a lo largo del tiempo.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('6887ccfa-4540-426c-9eb1-992873d2d6cf', 'd755f7e0-ed6e-46e9-9be1-eaab302eb1fb', 'OA2', 'conocimiento', 'Ciencias de la Vida', 'Representar, por medio de modelos, la transferencia de energía y materia desde los organismos fotosintéticos a otros seres vivos por medio de cadenas y redes alimentarias en diferentes ecosistemas.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('a5b35d55-7cd4-4056-a002-2b9f2a80d778', 'd755f7e0-ed6e-46e9-9be1-eaab302eb1fb', 'OA3', 'conocimiento', 'Ciencias de la Vida', 'Analizar los efectos de la actividad humana sobre las redes alimentarias.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('5b3d01f0-dfcd-497f-b174-fa8e3747fc05', 'd755f7e0-ed6e-46e9-9be1-eaab302eb1fb', 'OA4', 'conocimiento', 'Ciencias de la Vida', 'Identificar y describir las funciones de las principales estructuras del sistema reproductor humano femenino y masculino.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('d1128c23-f842-47a7-8d5b-172a7e5a69a2', 'd755f7e0-ed6e-46e9-9be1-eaab302eb1fb', 'OA5', 'conocimiento', 'Ciencias de la Vida', 'Describir y comparar los cambios que se producen en la pubertad en mujeres y hombres, reconociéndola como una etapa del desarrollo humano.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('9652c628-69c0-4596-a9f7-7347719b2759', 'd755f7e0-ed6e-46e9-9be1-eaab302eb1fb', 'OA6', 'conocimiento', 'Ciencias de la Vida', 'Reconocer los beneficios de realizar actividad física en forma regular y de cuidar la higiene corporal en el período de la pubertad.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('bb482e07-568e-4b22-8114-54d46b8450f0', 'd755f7e0-ed6e-46e9-9be1-eaab302eb1fb', 'OA7', 'conocimiento', 'Ciencias de la Vida', 'Investigar y comunicar los efectos nocivos de algunas drogas para la salud, proponiendo conductas de protección.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('883433d5-5322-4136-a058-ac23211cce80', 'd755f7e0-ed6e-46e9-9be1-eaab302eb1fb', 'OA8', 'conocimiento', 'Ciencias de la Vida', 'Explicar que la energía es necesaria para que los objetos cambien y los seres vivos realicen sus procesos vitales, y que la mayoría de los recursos energéticos proviene directa o indirectamente del Sol, dando ejemplos de ello.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('ab952e8d-1f1b-40e0-bf60-30aa34832fe6', 'd755f7e0-ed6e-46e9-9be1-eaab302eb1fb', 'OA9', 'conocimiento', 'Ciencias Físicas y Químicas', 'Investigar en forma experimental la transformación de la energía de una forma a otra, dando ejemplos y comunicando sus conclusiones. 10 Demostrar, por medio de la investigación experimental, que el calor fluye de un objeto caliente a uno frío hasta que ambos alcanzan la misma temperatura. 11 Clasificar los recursos naturales energéticos en no renovables y renovables y proponer medidas para el uso responsable de la energía. 12 Explicar, a partir de modelos, que la materia está formada por partículas en movimiento en sus estados sólido, líquido y gaseoso. 13 Demostrar, mediante la investigación experimental, los cambios de estado de la materia, como fusión, evaporación, ebullición, condensación, solidificación y sublimación. 14 Diferenciar entre calor y temperatura, considerando que el calor es una forma de energía y la temperatura es la medida de lo caliente de un objeto. 15 Medir e interpretar la información obtenida al calentar y enfriar el agua, considerando las transformaciones de un estado a otro. las características de las capas de la Tierra (atmósfera, litósfera e ) que posibilitan el desarrollo de la vida y proveen recursos para el ser humano, y proponer medidas de protección de dichas capas. experimentalmente la formación del suelo, sus propiedades (como color, textura y capacidad de retención de agua) y la importancia de protegerlo de la contaminación, comunicando sus resultados. 18 Explicar las consecuencias de la erosión sobre la superficie de la Tierra, identificando los agentes que la provocan, como el viento, el agua y las actividades humanas. e una asignatura enfermedades cardiovasculares y cardiorrespiratorias. ue se enmarca en el ser humano. A partir Para lograr los propósitos descritos, las') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_subjects (id, slug, nombre, total_grados) VALUES ('aeb141f8-dd82-4341-b229-3312d4959f11', 'educacion_fisica_salud', 'Educación Física y Salud', 6) ON CONFLICT (id) DO UPDATE SET slug = EXCLUDED.slug, nombre = EXCLUDED.nombre, total_grados = EXCLUDED.total_grados;
INSERT INTO curriculum_grades (id, subject_id, grado, label, total_objetivos) VALUES ('cd6833ac-bb9b-49aa-87e8-75bbdb5658e9', 'aeb141f8-dd82-4341-b229-3312d4959f11', '1', '1° Básico', 9) ON CONFLICT (id) DO UPDATE SET subject_id = EXCLUDED.subject_id, grado = EXCLUDED.grado, label = EXCLUDED.label, total_objetivos = EXCLUDED.total_objetivos;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('b86c877d-52ad-4aa8-98e2-b703b013ed3e', 'cd6833ac-bb9b-49aa-87e8-75bbdb5658e9', 'OA1', 'conocimiento', '', 'Demostrar habilidades motrices básicas de locomoción, manipulación y estabilidad en una variedad de juegos y actividades físicas, como saltar con dos pies en una dirección, caminar y correr alternadamente, lanzar y recoger un balón, caminar sobre una línea manteniendo el control del cuerpo, realizar suspensiones, giros y rodadas o volteos.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('feefc322-d768-4380-9455-72f362e3c1d6', 'cd6833ac-bb9b-49aa-87e8-75bbdb5658e9', 'OA2', 'conocimiento', 'Habilidades motrices', 'Ejecutar acciones motrices en relación a sí mismo, a un objeto o un compañero, usando diferentes categorías de ubicación espacial y temporal, como derecha, izquierda, adelante, atrás, arriba, abajo, adentro, afuera, entre, al lado, antes, durante, después, rápido y lento.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('dc30f7c3-f13d-4c68-8f8e-9c4e219a64e6', 'cd6833ac-bb9b-49aa-87e8-75bbdb5658e9', 'OA3', 'conocimiento', 'Habilidades motrices', 'Practicar una amplia gama de juegos con y sin oposición, con y sin colaboración, de persecución, individuales y colectivos.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('7865515f-f32d-42b4-b2e0-319b84a75c08', 'cd6833ac-bb9b-49aa-87e8-75bbdb5658e9', 'OA4', 'conocimiento', 'Habilidades motrices', 'Ejecutar habilidades motrices básicas en diferentes entornos, como las plazas activas, el patio del colegio, parques, playas, entre otros.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('804fd4c3-81fb-4047-af87-f230e306a0eb', 'cd6833ac-bb9b-49aa-87e8-75bbdb5658e9', 'OA5', 'conocimiento', 'Habilidades motrices', 'Ejecutar movimientos corporales, expresando sensaciones, ideas, estados de ánimo y emociones en variados espacios y a diferentes ritmos.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('002be988-5431-4191-a854-f39b60242ee6', 'cd6833ac-bb9b-49aa-87e8-75bbdb5658e9', 'OA6', 'conocimiento', 'Vida activa y saludable', 'Ejecutar actividades físicas de intensidad moderada a vigorosa que incrementen la condición física, por medio de juegos y circuitos.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('8be96223-75e8-4587-a99e-e9469c8ae280', 'cd6833ac-bb9b-49aa-87e8-75bbdb5658e9', 'OA7', 'conocimiento', 'Vida activa y saludable', 'Practicar en su vida cotidiana de forma guiada actividades físicas de intensidad moderada a vigorosa por medio de juegos tradicionales y actividades lúdicas.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('0d788b2c-f191-431b-b900-fce7beb85323', 'cd6833ac-bb9b-49aa-87e8-75bbdb5658e9', 'OA8', 'conocimiento', 'Vida activa y saludable', 'Reconocer las sensaciones y respuestas corporales provocadas por la práctica de actividad física, como cambios del color de la piel, sudor, agitación, ritmo de respiración, cansancio y dificultad al hablar.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('85394939-ca07-42c9-8f1f-747b5727e087', 'cd6833ac-bb9b-49aa-87e8-75bbdb5658e9', 'OA9', 'conocimiento', 'Vida activa y saludable', 'Practicar actividades físicas en forma segura, demostrando la adquisición de hábitos de higiene, posturales y de vida saludable, como lavarse las manos y la cara después de la clase, mantener una correcta postura y comer una colación saludable antes y luego de la práctica de actividad física. os o actividades motrices para aprender a trabajar en equipo, rentes roles (respetar al otro, recoger los materiales solicitados o liderar si se le asigna ese rol). 11 Practicar actividades físicas, demostrando comportamientos seguros, como: úrealizar un calentamiento mediante un juego úescuchar y seguir instrucciones úutilizar implementos bajo supervisión úmantener su posición dentro de los límites establecidos para la actividad') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_grades (id, subject_id, grado, label, total_objetivos) VALUES ('4abbfde5-c7db-4bf5-81b9-f4343d0ef096', 'aeb141f8-dd82-4341-b229-3312d4959f11', '2', '2° Básico', 9) ON CONFLICT (id) DO UPDATE SET subject_id = EXCLUDED.subject_id, grado = EXCLUDED.grado, label = EXCLUDED.label, total_objetivos = EXCLUDED.total_objetivos;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('e99c9ca4-5a7b-45ac-ac3c-5fa2b901756d', '4abbfde5-c7db-4bf5-81b9-f4343d0ef096', 'OA1', 'conocimiento', '', 'Demostrar habilidades motrices básicas de locomoción, manipulación y estabilidad en diferentes direcciones, alturas y niveles, como saltar de forma continua en un pie y luego en el otro, botear un balón mientras camina, mantener el equilibrio sobre una base a una pequeña altura, realizar suspensiones, giros y rodadas o volteos.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('c7a1d5fb-2a94-4a3a-98e6-cc3c68de6674', '4abbfde5-c7db-4bf5-81b9-f4343d0ef096', 'OA2', 'conocimiento', 'Habilidades motrices', 'Ejecutar acciones motrices que presenten una solución a un problema, por ejemplo, agrupaciones, representaciones de símbolos, letras, números o figuras geométricas.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
