INSERT INTO curriculum_grades (id, subject_id, grado, label, total_objetivos) VALUES ('a8616bfb-b9ca-4034-be6f-ab064f259989', 'aeb141f8-dd82-4341-b229-3312d4959f11', '3', '3° Básico', 9) ON CONFLICT (id) DO UPDATE SET subject_id = EXCLUDED.subject_id, grado = EXCLUDED.grado, label = EXCLUDED.label, total_objetivos = EXCLUDED.total_objetivos;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('9c9b1708-3c83-4772-aaad-86d98c0e0b77', 'a8616bfb-b9ca-4034-be6f-ab064f259989', 'OA1', 'conocimiento', '', 'Demostrar capacidad para ejecutar de forma combinada las habilidades motrices básicas de locomoción, manipulación y estabilidad en diferentes direcciones, alturas y niveles, como correr y lanzar un objeto con una mano, caminar sobre una línea y realizar un giro de 180° en un pie.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('16cdb285-d1d9-49b5-9c99-e37f4f008bda', 'a8616bfb-b9ca-4034-be6f-ab064f259989', 'OA2', 'conocimiento', 'Habilidades motrices', 'Ejecutar acciones motrices que presenten una solución a un problema, reconociendo diversos criterios (tiempo, espacio y números de personas), por ejemplo, juegos de uno contra uno, juegos en grupos reducidos y juegos con superioridad numérica.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('23489051-aad7-4a08-b527-062bf7aa6057', 'a8616bfb-b9ca-4034-be6f-ab064f259989', 'OA3', 'conocimiento', 'Habilidades motrices', 'Practicar juegos pre-deportivos con reglas y espacios adaptados, aplicando los principios generales de juego, como avanzar y retroceder en bloque, recuperar el balón, acompañar la jugada y la visión periférica.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('e4e9af14-f1f3-4e2e-b106-2df24cbdd1aa', 'a8616bfb-b9ca-4034-be6f-ab064f259989', 'OA4', 'conocimiento', 'Habilidades motrices', 'Ejecutar actividades físicas y/o lúdicas en diferentes entornos, aplicando medidas para conservar limpios y ordenados los espacios, por ejemplo:') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objective_items (objective_id, orden, descripcion) VALUES ('e4e9af14-f1f3-4e2e-b106-2df24cbdd1aa', 1, 'jugar en plazas activas') ON CONFLICT (objective_id, orden) DO UPDATE SET descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objective_items (objective_id, orden, descripcion) VALUES ('e4e9af14-f1f3-4e2e-b106-2df24cbdd1aa', 2, 'jugar un partido en la plaza o la playa') ON CONFLICT (objective_id, orden) DO UPDATE SET descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objective_items (objective_id, orden, descripcion) VALUES ('e4e9af14-f1f3-4e2e-b106-2df24cbdd1aa', 3, 'realizar caminatas en el entorno natural') ON CONFLICT (objective_id, orden) DO UPDATE SET descripcion = EXCLUDED.descripcion;
