INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('aa112cb9-38b3-40c2-8e01-3cfd421b8b5e', 'a8616bfb-b9ca-4034-be6f-ab064f259989', 'OA5', 'conocimiento', 'Habilidades motrices', 'Ejecutar movimientos o elementos de danzas tradicionales de forma coordinada, utilizando actividades rítmicas y lúdicas de forma individual o grupal.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('e6d3a261-6e78-4386-bca3-40f481f68f21', 'a8616bfb-b9ca-4034-be6f-ab064f259989', 'OA6', 'conocimiento', 'Vida activa y saludable', 'Ejecutar actividades físicas de intensidad moderada a vigorosa que desarrollen la condición física por medio de la práctica de ejercicios de resistencia cardiovascular, fuerza, flexibilidad y velocidad, mejorando sus resultados personales.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('3f28cef6-b91c-4c41-9cc0-1b1a8e90a814', 'a8616bfb-b9ca-4034-be6f-ab064f259989', 'OA7', 'conocimiento', 'Vida activa y saludable', 'Practicar de manera regular y autónoma actividades físicas de intensidad moderada a vigorosa, como saltar la cuerda y caminar hasta el colegio.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('4ff6008d-0057-4462-a93d-043c438e01e2', 'a8616bfb-b9ca-4034-be6f-ab064f259989', 'OA8', 'conocimiento', 'Vida activa y saludable', 'Describir y registrar las respuestas corporales provocadas por la práctica de actividad física, como aumento de la frecuencia cardiaca y respiratoria.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('0c8d4a7e-60bc-4147-b9ce-b0fe95560acf', 'a8616bfb-b9ca-4034-be6f-ab064f259989', 'OA9', 'conocimiento', 'Vida activa y saludable', 'Practicar actividades físicas en forma segura, demostrando la adquisición de hábitos de higiene, posturales y de vida saludable, como utilizar protección solar, lavarse y cambiarse de ropa después de la clase, hidratarse con agua, comer una colación saludable después de la práctica de actividad física. vidades físicas y /o juegos colectivos con responsabilidad y honesndo las reglas, los roles asignados y los principios de un juego limpio. vidades físicas, demostrando comportamientos seguros, como:') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objective_items (objective_id, orden, descripcion) VALUES ('0c8d4a7e-60bc-4147-b9ce-b0fe95560acf', 1, 'participar en actividades de calentamiento en forma apropiada') ON CONFLICT (objective_id, orden) DO UPDATE SET descripcion = EXCLUDED.descripcion;
