INSERT INTO curriculum_objective_items (objective_id, orden, descripcion) VALUES ('0c8d4a7e-60bc-4147-b9ce-b0fe95560acf', 3, 'mantener su posición dentro de los límites establecidos para la actividad') ON CONFLICT (objective_id, orden) DO UPDATE SET descripcion = EXCLUDED.descripcion;
