INSERT INTO curriculum_grades (id, subject_id, grado, label, total_objetivos) VALUES ('548a3762-ccb4-4d9d-b096-1b6e85e8923f', 'aeb141f8-dd82-4341-b229-3312d4959f11', '4', '4° Básico', 5) ON CONFLICT (id) DO UPDATE SET subject_id = EXCLUDED.subject_id, grado = EXCLUDED.grado, label = EXCLUDED.label, total_objetivos = EXCLUDED.total_objetivos;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('dbb1151d-c8b6-4a90-a8d4-3bb6283ea90e', '548a3762-ccb4-4d9d-b096-1b6e85e8923f', 'OA1', 'conocimiento', '', 'Demostrar control en la ejecución de las habilidades motrices básicas de locomoción, manipulación y estabilidad en diferentes direcciones, alturas y niveles, por ejemplo, atrapar un objeto con una mano a diferentes alturas, desplazarse boteando un objeto en zig-zag y saltar, caminar sobre una base a una pequeña altura y realizar un giro de 360° en un solo pie.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('2df0c8c8-2513-4579-9f35-379b0f891725', '548a3762-ccb4-4d9d-b096-1b6e85e8923f', 'OA2', 'conocimiento', 'Habilidades motrices', 'Ejecutar juegos colectivos y crear estrategias con el apoyo del docente para resolver problemas en relación al tiempo, el espacio y el número de personas, por ejemplo, dar cinco pases sin que el equipo rival lo intercepte o sin que el objeto caiga.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('6a1d0be5-6429-4e08-8e22-fcf82c43265a', '548a3762-ccb4-4d9d-b096-1b6e85e8923f', 'OA3', 'conocimiento', 'Habilidades motrices', 'Practicar juegos pre-deportivos con reglas y espacios adaptados, aplicando los principios generales de juego, como acoplarse en ataque y replegarse en defensa, utilizar el campo de juego a lo largo y ancho o reconocer el espacio del adversario.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
