INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('269d14ab-155e-4682-b220-10ff2564f5d6', '548a3762-ccb4-4d9d-b096-1b6e85e8923f', 'OA5', 'conocimiento', 'Habilidades motrices', 'Ejecutar movimientos o elementos de danzas tradicionales de forma coordinada, utilizando actividades rítmicas y lúdicas de forma individual o grupal. vidades físicas de intensidad moderada a vigorosa que desarrollen física por medio de la práctica de ejercicios de resistencia cardiovascular, fuerza, flexibilidad y velocidad, mejorando sus resultados personales. 7 Practicar de manera regular y autónoma actividades físicas de intensidad moderada a vigorosa, como saltar la cuerda y caminar hasta el colegio. 8 Medir y registrar las respuestas corporales provocadas por la actividad física mediante el pulso o utilizando escalas de percepción de esfuerzo. 9 Practicar actividades físicas en forma segura, demostrando la adquisición de hábitos de higiene, posturales y de vida saludable, como utilizar protección solar, lavarse y cambiarse de ropa después de la clase, hidratarse con agua, comer una colación saludable después de la práctica de actividad física. vidades físicas y /o juegos colectivos con responsabilidad y honesndo las reglas y los roles asignados, respetando las decisiones de la autoridad y organizar equitativamente los equipos. vidades físicas, demostrando comportamientos seguros, como: úrealizar un calentamiento en forma apropiada úutilizar de manera adecuada los materiales y las instalaciones para evitar el riesgo personal y de otros úescuchar y seguir instrucciones úasegurar que el espacio está libre de obstáculos') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
