INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('527a0059-ea17-46b6-ba67-c98e7c31655e', 'b6cf8a34-e9ff-430c-b7b5-3dc37f8402e0', 'OA1', 'conocimiento', '', 'Demostrar la aplicación de las habilidades motrices básicas adquiridas, en una variedad de actividades deportivas, por ejemplo, realizar un giro sobre una viga de equilibrio, lanzar un balón hacia la portería y correr una distancia determinada (por ejemplo, 50 u 80 metros).') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('07504ccc-4c75-4aff-8e79-6d7dadc707f5', 'b6cf8a34-e9ff-430c-b7b5-3dc37f8402e0', 'OA2', 'conocimiento', 'Habilidades motrices', 'Ejecutar juegos colectivos y deportes, creando tácticas y estrategias y demostrando formas para resolver un problema en relación al espacio, el objeto y los adversarios, por ejemplo, dar tres pases en cinco segundos o dar tres pasos y dar un pase a un compañero.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
