INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('46c69129-2c6e-41f2-a4fc-f8e4e37364b5', 'b6cf8a34-e9ff-430c-b7b5-3dc37f8402e0', 'OA5', 'conocimiento', 'Habilidades motrices', 'Demostrar la correcta ejecución de una danza nacional, utilizando pasos básicos y música folclórica de forma individual o grupal, por ejemplo, danzas de la zona norte, central, sur e Isla de Pascua. vidades físicas de intensidad moderada a vigorosa que desarrollen física por medio de la práctica de ejercicios de resistencia cardiovascular, fuerza, flexibilidad y velocidad, estableciendo metas de superación personal. 7 Practicar y planificar de forma regular actividades físicas y/o deportivas de intensidad moderada a vigorosa, como planificar un partido, participar en una caminata o corrida familiar e integrar talleres deportivos. 8 Determinar la intensidad del esfuerzo físico de forma manual, mediante el pulso o utilizando escalas de percepción de esfuerzo. 9 Practicar actividades físicas en forma segura, demostrando la adquisición de hábitos de higiene, posturales y de vida saludable, como utilizar una ropa distinta para la clase, mantener una correcta postura, utilizar protectores solares e hidratarse con agua antes, durante y después de la clase. vidades físicas y /o juegos colectivos, demostrando responsabiliy respeto al participar, por ejemplo: conversar y plantear discrepancias, aceptar las diferencias individuales e intentar llegar a acuerdos, jugar rativa, aceptar el resultado y manejar el triunfo. 11 Practicar actividades físicas y/o deportivas, demostrando comportamientos seguros y un manejo adecuado de los materiales y los procedimientos, como: úrealizar un calentamiento específico individual o grupal úusar ropa adecuada para la actividad úcuidar sus pertenencias úmanipular de forma segura los implementos y las instalaciones Básico Sexto') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
