INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('da89e17f-376a-47a8-83cb-8776785bf9f7', 'c25ccb9e-cfad-4088-9226-da1daa2b2b84', 'OA1', 'conocimiento', '', 'Demostrar la aplicación de las habilidades motrices básicas adquiridas, en una variedad de actividades deportivas, por ejemplo, realizar un giro sobre una viga de equilibrio, lanzar un balón hacia la portería y correr una distancia determinada (por ejemplo, 50 u 80 metros), superando pequeños obstáculos.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('d06018d8-ddee-4cf1-a538-d00c3a2792f7', 'c25ccb9e-cfad-4088-9226-da1daa2b2b84', 'OA2', 'conocimiento', 'Habilidades motrices', 'Ejecutar juegos colectivos y deportes que requieran tomar decisiones y evaluar las estrategias utilizadas para perfeccionar su juego, por ejemplo, aplicar las orientaciones dadas por el profesor durante el tiempo solicitado o reglamentado durante el juego.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('c9a50c0e-96af-4a34-92a0-3e3c58c1806e', 'c25ccb9e-cfad-4088-9226-da1daa2b2b84', 'OA3', 'conocimiento', 'Habilidades motrices', 'Practicar deportes individuales y colectivos que apliquen reglas y estrategias específicas del juego, por ejemplo, generar superioridad numérica, cambiar la posición o la función de los jugadores durante el partido.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
