INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('71feb3f7-210a-46ab-a651-d53ae523466d', 'c25ccb9e-cfad-4088-9226-da1daa2b2b84', 'OA_c', 'habilidad', 'Habilidades motrices', 'Localizar a Chile en mapamundis o globos terráqueos y distinguir diferentes representaciones de la Tierra.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('0c96dbff-1775-4aac-82f5-746297659bba', 'c25ccb9e-cfad-4088-9226-da1daa2b2b84', 'OA_d', 'habilidad', 'Habilidades motrices', 'Orientarse en el espacio, utilizando categorías de ubicación relativa (derecha, izquierda, lejos, cerca, delante, detrás, arriba, abajo, adentro, afuera). mación explícita sobre su entorno a partir de fuentes orales y s (narraciones, fotografías, medios audiovisuales), mediante preguntas dirigidas.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('4af27d09-a470-4101-8133-43caecac79e4', 'c25ccb9e-cfad-4088-9226-da1daa2b2b84', 'OA_f', 'habilidad', 'Habilidades motrices', 'Formular opiniones sobre situaciones del presente y del pasado, propias de su entorno familiar, escolar o local, y sobre otros temas de su interés.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('bd40f4b2-1e85-4ddb-a818-5d28e257cfc9', 'c25ccb9e-cfad-4088-9226-da1daa2b2b84', 'OA_g', 'habilidad', 'Habilidades: Comunicación', 'Comunicar oralmente temas de su interés, experiencias personales o información sobre sí mismos, de manera clara y coherente.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_subjects (id, slug, nombre, total_grados) VALUES ('dcddbbf8-21ad-4c4f-8da1-8496fdf657b1', 'historia_geografia_cs_sociales', 'Historia, Geografía y Ciencias Sociales', 6) ON CONFLICT (id) DO UPDATE SET slug = EXCLUDED.slug, nombre = EXCLUDED.nombre, total_grados = EXCLUDED.total_grados;
INSERT INTO curriculum_grades (id, subject_id, grado, label, total_objetivos) VALUES ('e3d4a093-47d6-4505-a3ff-e21053c15c5a', 'dcddbbf8-21ad-4c4f-8da1-8496fdf657b1', '1', '1° Básico', 15) ON CONFLICT (id) DO UPDATE SET subject_id = EXCLUDED.subject_id, grado = EXCLUDED.grado, label = EXCLUDED.label, total_objetivos = EXCLUDED.total_objetivos;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('60d7b08c-adcd-4ce6-aaee-c80c569ca6fb', 'e3d4a093-47d6-4505-a3ff-e21053c15c5a', 'OA1', 'conocimiento', 'Historia', 'Nombrar y secuenciar días de la semana y meses del año, utilizando calendarios, e identificar el año en curso.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('49175d1b-0616-4696-99c5-a1714ba4efc5', 'e3d4a093-47d6-4505-a3ff-e21053c15c5a', 'OA2', 'conocimiento', 'Historia', 'Secuenciar acontecimientos y actividades de la vida cotidiana, personal y familiar, utilizando categorías relativas de ubicación temporal, como antes, después; ayer, hoy, mañana; día, noche; este año, el año pasado, el año próximo.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('f6e8b401-93df-4165-884f-a1680736ac73', 'e3d4a093-47d6-4505-a3ff-e21053c15c5a', 'OA3', 'conocimiento', 'Historia', 'Registrar y comunicar información sobre elementos que forman parte de su identidad personal (nombre, fecha de nacimiento, lugar de procedencia, ascendencias, gustos, intereses, amigos y otros) para reconocer sus características individuales.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('4f117847-66a0-4ad6-ae2a-db64749e8135', 'e3d4a093-47d6-4505-a3ff-e21053c15c5a', 'OA4', 'conocimiento', 'Historia', 'Obtener y comunicar aspectos de la historia de su familia y sus características, como costumbres, tradiciones, ritos, fiestas, recuerdos y roles que desempeñan los distintos miembros de su grupo familiar, mediante la formulación de preguntas a adultos de su entorno cercano.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('305d6256-564a-46ef-a453-c423ca66802e', 'e3d4a093-47d6-4505-a3ff-e21053c15c5a', 'OA5', 'conocimiento', 'Historia', 'Reconocer los símbolos representativos de Chile (como la bandera, el escudo y el himno nacional), describir costumbres, actividades y la participación de hombres y mujeres respecto de conmemoraciones nacionales (como Fiestas Patrias, Día del Descubrimiento de dos mundos y Combate Naval de Iquique) y reconocer en ellos un elemento de unidad e identidad nacional.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('fbed2f34-22ca-4fb4-aa11-16d251755d46', 'e3d4a093-47d6-4505-a3ff-e21053c15c5a', 'OA6', 'conocimiento', 'Historia', 'Conocer expresiones culturales locales y nacionales (como comidas, flores y animales típicos, música y juegos, entre otros), describir fiestas y tradiciones importantes de nivel local (como Fiesta de La Tirana, Fiesta de San Pedro, Fiesta de Cuasimodo, carreras a la chilena, el rodeo, la vendimia y la fundación del pueblo o de la ciudad, entre otras) y reconocer estas expresiones como elementos de unidad e identidad local y/o nacional.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('c2497026-f131-4d52-92c8-3e75add1e24e', 'e3d4a093-47d6-4505-a3ff-e21053c15c5a', 'OA7', 'conocimiento', 'Historia', 'Conocer sobre la vida de hombres y mujeres que han contribuido a la sociedad chilena en diversos ámbitos; por ejemplo, los fundadores de las ciudades, los exploradores, las personas que han fundado o creado instituciones, las personas que se han destacado por su emprendimiento y su solidaridad, los deportistas, los científicos, los artistas y los grandes poetas, entre otros. mapas y los planos son formas de representar lugares. e en mapas, incluyendo la cordillera de los Andes, el océano Pacífico, la ciudad de Santiago, su región, su capital y su localidad. r paisajes de su entorno local, utilizando vocabulario geoaís, ciudad, camino, pueblo, construcciones, cordillera, esierto) y categorías de ubicación relativa (derecha, izquier- , entre otros). s y productos de su familia y su localidad y cómo estos apora, reconociendo la importancia de todos los trabajos, tanto remunerados. otros niños en diferentes partes del mundo por medio de ubicando en un globo terráqueo o mapamundi los países parando su idioma, vestimenta, comida, fiestas, costumtareas con las de niños chilenos. realizar acciones concretas en su entorno cercano (familia, ) que reflejen: úrespeto al otro (ejemplos: escuchar atentamente al otro, tratar con cortesía a los demás, etc.) úempatía (ejemplos: ayudar a los demás cuando sea necesario, no discriminar a otros por su aspecto o costumbres, etc.) úresponsabilidad (ejemplos: asumir encargos en su casa y en la sala de clases, cuidar sus pertenencias y la de los demás, cuidar los espacios comunes, etc.) algunas normas para la buena convivencia y para la seguridad su familia, en la escuela y en la vía pública. r que cumplen, en beneficio de la comunidad, instituciones municipalidad, el hospital o la posta, Carabineros de Chile, trabajan en ellas.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('870f3e12-9b24-4028-8b4c-ac3c34c6335d', 'e3d4a093-47d6-4505-a3ff-e21053c15c5a', 'OA_a', 'habilidad', 'Geografía', 'Secuenciar cronológicamente eventos significativos ocurridos en la escuela o la comunidad durante el año y leer líneas de tiempo simples.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('032d23e2-646c-469e-85fe-c52046efe1d2', 'e3d4a093-47d6-4505-a3ff-e21053c15c5a', 'OA_b', 'habilidad', 'Habilidades: Pensamiento temporal y espacial', 'Aplicar conceptos relacionados con el tiempo (pasado, presente, futuro, días, semanas, meses, años, antiguamente, este año, el año pasado, el año próximo).') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('234a8d30-cc8a-454c-92bc-67e5f483151d', 'e3d4a093-47d6-4505-a3ff-e21053c15c5a', 'OA_c', 'habilidad', 'Habilidades: Pensamiento temporal y espacial', 'Identificar elementos de continuidad y cambio entre modos de vida del pasado y del presente.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('c594ac00-22f1-4cc6-b663-8ebda810f005', 'e3d4a093-47d6-4505-a3ff-e21053c15c5a', 'OA_d', 'habilidad', 'Habilidades: Pensamiento temporal y espacial', 'Leer y comunicar información geográfica mediante distintas herramientas (planos, mapas, globos terráqueos y diagramas).') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('bdc141aa-45fa-4169-990a-9097784858db', 'e3d4a093-47d6-4505-a3ff-e21053c15c5a', 'OA_e', 'habilidad', 'Habilidades: Pensamiento temporal y espacial', 'Orientarse en el espacio, utilizando categorías de ubicación relativa (derecha, izquierda, lejos, cerca) y asociando referentes locales (cordillera, cerro, mar u otros) a los puntos cardinales. Obtener información explícita sobre el pasado y el presente a partir de imágenes y de fuentes escritas y orales dadas (narraciones, relatos históricos, leyendas, imágenes, mapas y preguntas a adultos cercanos), mediante preguntas dirigidas.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('aa286059-bba7-4a80-bc2e-56fda692e7c2', 'e3d4a093-47d6-4505-a3ff-e21053c15c5a', 'OA_g', 'habilidad', 'Habilidades: Análisis y trabajo con fuentes', 'Formular opiniones justificadas sobre temas de su interés.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('70cf0e2e-22f0-4f7f-8334-1e09a3fa7c4e', 'e3d4a093-47d6-4505-a3ff-e21053c15c5a', 'OA_h', 'habilidad', 'Habilidades: Comunicación', 'Participar en conversaciones grupales, respetando turnos y otros puntos de vista.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('c17d124f-03f6-4698-a609-0c7ea0b36038', 'e3d4a093-47d6-4505-a3ff-e21053c15c5a', 'OA_i', 'habilidad', 'Habilidades: Comunicación', 'Presentar temas dados en forma oral, visual o escrita, incorporando material de apoyo.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_grades (id, subject_id, grado, label, total_objetivos) VALUES ('fd54e4b5-5f9b-4816-9600-facd32280ff1', 'dcddbbf8-21ad-4c4f-8da1-8496fdf657b1', '2', '2° Básico', 16) ON CONFLICT (id) DO UPDATE SET subject_id = EXCLUDED.subject_id, grado = EXCLUDED.grado, label = EXCLUDED.label, total_objetivos = EXCLUDED.total_objetivos;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('61363250-749f-4020-b9b4-98ba69dad6a5', 'fd54e4b5-5f9b-4816-9600-facd32280ff1', 'OA1', 'conocimiento', 'Historia', 'Describir los modos de vida de algunos pueblos originarios de Chile en el período precolombino, incluyendo ubicación geográfica, medio natural en que habitaban, vida nómade o sedentaria, roles de hombres y mujeres, herramientas y tecnología, principales actividades, vivienda, costumbres, idioma, creencias, alimentación y fiestas, entre otros.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('6561c80a-4a88-41ee-b40b-db5c72c71b75', 'fd54e4b5-5f9b-4816-9600-facd32280ff1', 'OA2', 'conocimiento', 'Historia', 'Comparar el modo de vida y expresiones culturales de pueblos indígenas presentes en Chile actual (como mapuche, aimara, rapa nui) con respecto al periodo precolombino, identificando aspectos de su cultura que se han mantenido hasta el presente y aspectos que han cambiado.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('36ede4ac-e105-4694-a4a5-9fa93e59884c', 'fd54e4b5-5f9b-4816-9600-facd32280ff1', 'OA3', 'conocimiento', 'Historia', 'Distinguir los diversos aportes a la sociedad chilena proveniente de los pueblos originarios (palabras, alimentos, tradiciones, cultura, etc.) y de los españoles (idioma, religión, alimentos, cultura, etc.) y reconocer nuestra sociedad como mestiza.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('70a79a16-fb0c-44de-8b32-8d88cfe348c8', 'fd54e4b5-5f9b-4816-9600-facd32280ff1', 'OA4', 'conocimiento', 'Historia', 'Reconocer y dar ejemplos de la influencia y los aportes de inmigrantes de distintas naciones europeas, orientales, árabes y latinoamericanas a la diversidad de la sociedad chilena, a lo largo de su historia.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('73ec0ee3-85a3-4881-bc3c-376cf7504d8e', 'fd54e4b5-5f9b-4816-9600-facd32280ff1', 'OA5', 'conocimiento', 'Historia', 'Reconocer diversas expresiones del patrimonio cultural del país y de su región, como manifestaciones artísticas, tradiciones folclóricas, leyendas y tradiciones orales, costumbres familiares, creencias, idioma, construcciones, comidas típicas, fiestas, monumentos y sitios históricos.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('99b54fea-846e-4eeb-af20-52f123a42a99', 'fd54e4b5-5f9b-4816-9600-facd32280ff1', 'OA6', 'conocimiento', 'Geografía', 'Leer y dibujar planos simples de su entorno, utilizando puntos de referencia, categorías de posición relativa y simbología pictórica.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('7c7b7d58-fc77-4d2a-954f-fb55728b145b', 'fd54e4b5-5f9b-4816-9600-facd32280ff1', 'OA7', 'conocimiento', 'Geografía', 'Ubicar Chile, Santiago, la propia región y su capital en el globo terráqueo o en mapas, y describir la ubicación relativa de países limítrofes y de otros países de América del Sur, utilizando los puntos cardinales.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('eaba4817-d6a9-4b10-ae71-e902990f1cb3', 'fd54e4b5-5f9b-4816-9600-facd32280ff1', 'OA8', 'conocimiento', 'Geografía', 'Clasificar y caracterizar algunos paisajes de Chile según su ubicación en la zona norte, centro y sur del país, observando imágenes, y utilizando diversas fuentes y un vocabulario geográfico adecuado (océano, río, cordillera de los Andes y de la Costa, desierto, valle, costa, volcán, archipiélago, isla, fiordo, lago, ciudad y pueblo, entre otros). expresiones del patrimonio natural de Chile y de su región, como paisajes, flora y fauna característica, y parques nacionales, entre otros. zonas habitadas por algunos pueblos originarios de Chile, norte, centro y sur. cipales características geográficas (disponibilidad de agua, ación) de las zonas habitadas por algunos pueblos originalos recursos que utilizaron para satisfacer sus necesidades de o y vivienda. realizar acciones concretas en su entorno cercano (familia, ) que reflejen: úrespeto al otro (interactuar con cortesía, cuidar espacios comunes, respetar la propiedad de los demás, etc.) úresponsabilidad (ejemplos: cumplir con sus deberes escolares, asumir encargos en el hogar y dentro de la sala de clases, etc.) útolerancia (ejemplos: respetar opiniones diversas, no discriminar a otros por su aspecto o costumbres, etc.) úempatía (ejemplos: integrar a los demás en sus juegos y actividades, ayudar a los otros, etc.) ta honesta en la vida cotidiana, en los juegos y en el blando con la verdad, respetando las reglas de los juegos sin nociendo sus errores y sus acciones, entre otros. aplicar y explicar la importancia de algunas normas neceúcuidarse, cuidar a otros y evitar situaciones de riesgo (como seguridad vial, vías de evacuación, adaptaciones para discapacitados, zonas de silencio, etc.) úorganizar un ambiente propicio al aprendizaje y acogedor para todos (por ejemplo, respetar los turnos, cuidar el espacio y las pertenencias comunes y de sus pares, etc.) úcuidar el patrimonio y el medioambiente r que cumplen en beneficio de la comunidad servicios como porte y de comunicación y el mercado, y algunas institucioroteger nuestro patrimonio cultural y natural. r acciones para cuidar y respetar los espacios públicos denscuela (como baños, patios, salas de clase, plazas, parques, tre otros), reconociendo que pertenecen y benefician a todos , su cuidado es responsabilidad de todos los miembros de la') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
