INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('a64d3bd6-98e2-4829-b49d-54cf3ce4b07f', 'fd54e4b5-5f9b-4816-9600-facd32280ff1', 'OA_b', 'habilidad', 'Habilidades: Pensamiento temporal y espacial', 'Aplicar conceptos relacionados con el tiempo (pasado, presente, futuro, años, décadas, siglos, antiguo, moderno, a.C., d.C.).') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('2a7686f0-effa-4cc8-89dd-c8b4db520cbc', 'fd54e4b5-5f9b-4816-9600-facd32280ff1', 'OA_c', 'habilidad', 'Habilidades: Pensamiento temporal y espacial', 'Comparar distintos aspectos (objetos, juegos, costumbres y actividades) entre sociedades y civilizaciones del pasado y del presente para identificar continuidades y cambios.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
