INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('d814e87c-90f1-4d9e-b35d-6a4b2859e204', 'fd54e4b5-5f9b-4816-9600-facd32280ff1', 'OA_e', 'habilidad', 'Habilidades: Pensamiento temporal y espacial', 'Orientarse en el espacio, utilizando referencias, categorías de ubicación relativa y puntos cardinales. Obtener información sobre el pasado y el presente a partir de diversas fuentes dadas (como entrevistas, narraciones, medios audiovisuales, mapas, textos, imágenes, gráficos, tablas y pictogramas, entre otros) y mediante preguntas dirigidas.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
