INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('1a81bd65-93f9-4450-afac-29b486b489c1', 'fd54e4b5-5f9b-4816-9600-facd32280ff1', 'OA_i', 'habilidad', 'Habilidades: Comunicación', 'Presentar, en forma oral, visual o escrita, temas de su interés o estudiados en el nivel, organizando la exposición e incorporando el material de apoyo pertinente.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_grades (id, subject_id, grado, label, total_objetivos) VALUES ('25ec11f9-064b-472b-8671-f8f87855897e', 'dcddbbf8-21ad-4c4f-8da1-8496fdf657b1', '3', '3° Básico', 17) ON CONFLICT (id) DO UPDATE SET subject_id = EXCLUDED.subject_id, grado = EXCLUDED.grado, label = EXCLUDED.label, total_objetivos = EXCLUDED.total_objetivos;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('71a6b7ae-2a3b-4dd8-bb95-e50721e2fc5d', '25ec11f9-064b-472b-8671-f8f87855897e', 'OA1', 'conocimiento', 'Historia', 'Reconocer aspectos de la vida cotidiana de la civilización griega de la Antigüedad e identificar algunos elementos de su legado a sociedades y culturas del presente; entre ellos, la organización democrática, el desarrollo de la historia, el teatro como forma de expresión, el arte y la escultura, la arquitectura, la mitología, la geometría y la filosofía, la creación del alfabeto y los juegos olímpicos.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('00b02059-ffb0-46bd-b078-b5a27b15e5be', '25ec11f9-064b-472b-8671-f8f87855897e', 'OA2', 'conocimiento', 'Historia', 'Reconocer aspectos de la vida cotidiana de la civilización romana de la Antigüedad e identificar algunos elementos de su legado a sociedades y culturas del presente; entre ellos, el idioma, el derecho y las leyes, el arte y las obras arquitectónicas.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('2ace7c0b-bba0-4a04-85ba-3985bb44e423', '25ec11f9-064b-472b-8671-f8f87855897e', 'OA3', 'conocimiento', 'Historia', 'Explicar, con ejemplos concretos, cómo diferentes culturas y pueblos (como griegos y romanos de la Antigüedad) han enfrentado de distintas maneras el desafío de desarrollarse y satisfacer las necesidades comunes a todos los seres humanos.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('38a4c66a-9f74-4921-963e-220775cf1849', '25ec11f9-064b-472b-8671-f8f87855897e', 'OA4', 'conocimiento', 'Historia', 'Comparar modos de vida de la Antigüedad con el propio, considerando costumbres, trabajos y oficios, creencias, vestimentas y características de las ciudades, entre otros.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('6a42ce6b-3404-41fd-a9cc-6d5c29a1288f', '25ec11f9-064b-472b-8671-f8f87855897e', 'OA5', 'conocimiento', 'Historia', 'Investigar sobre algún tema de su interés con relación a las civilizaciones estudiadas (como los héroes, los dioses, las ciudades, las viviendas, la vestimenta, las herramientas tecnológicas y la esclavitud, entre otros) por medio de diferentes fuentes (libros, fuentes gráficas, TICs) y comunicar lo aprendido.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('c8575413-a26c-4024-a32b-f6177a3b91e5', '25ec11f9-064b-472b-8671-f8f87855897e', 'OA6', 'conocimiento', 'Geografía', 'Ubicar personas, lugares y elementos en una cuadrícula, utilizando líneas de referencia y puntos cardinales.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('0a6b2a07-61bd-4ad3-80df-b1689dce37ae', '25ec11f9-064b-472b-8671-f8f87855897e', 'OA7', 'conocimiento', 'Geografía', 'Distinguir hemisferios, círculo del Ecuador, trópicos, polos, continentes y océanos del planeta en mapas y globos terráqueos.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('ed2f0b3f-2679-4267-b0e7-5256e0f3e99e', '25ec11f9-064b-472b-8671-f8f87855897e', 'OA8', 'conocimiento', 'Geografía', 'Identificar y ubicar en mapas las principales zonas climáticas del mundo, y dar ejemplos de distintos paisajes que pueden encontrarse en estas zonas y de cómo las personas han elaborado diferentes estrategias para habitarlos. torno geográfico de las civilizaciones estudiadas, utilizando vocabulario geográfico adecuado (continente, valle, montaña, océano, río, archipiélago, mares, península, ciudad, construcciones y monumentos, entre otros). actores geográficos que influyeron en el desarrollo de las diadas (ubicación, relieve y clima, recursos naturales dispodel mar Egeo y sus islas para Grecia e importancia del mar oma, entre otros). y responsabilidades como estudiante y en situaciones de la o cumplir con sus deberes escolares, colaborar en el orden los espacios que comparte con su familia, escuela y comuertenencias y las de los demás, preocuparse de su salud e su casa. realizar acciones concretas en su entorno cercano (familia, ) que reflejen valores y virtudes ciudadanas, como: úla tolerancia y el respeto al otro (ejemplos: respetar las opiniones distintas a las propias, mostrar disposición al diálogo, respetar expresiones de diversidad, como diferentes costumbres, creencias, origen étnico, nacionalidad, etc.) úla empatía (ejemplos: demostrar cortesía con los demás, escuchar al otro, ayudar a quien lo necesite, etc.) ta honesta en la vida cotidiana, en los juegos y en el blando con la verdad, respetando las reglas de los juegos sin nociendo sus errores y sus acciones, entre otros. iños tienen derechos que les permiten recibir un cuidado de la sociedad con el fin de que puedan aprender, crecer y r ejemplos de cómo la sociedad les garantiza estos derechos. car sus resultados sobre algunas instituciones públicas y eb, Sernac, SII, Banco Estado, instituciones de previsión y s, Hogar de Cristo y fundaciones, entre otras), identificando stan en la comunidad y los diferentes trabajos que realizan desempeñan en ellas. ble y activamente en su hogar (encargos, celebraciones, cuiy en la escuela (campañas solidarias, celebraciones, deportes y compromisos y responsabilidades adquiridos.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
