INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('2a27f439-1f16-4932-bd02-ede33d0212fd', '25ec11f9-064b-472b-8671-f8f87855897e', 'OA_b', 'habilidad', 'Habilidades: Pensamiento temporal y espacial', 'Aplicar conceptos relacionados con el tiempo (pasado, presente, futuro, décadas, antiguo, moderno, siglos, períodos, hitos).') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('f44c9675-1bf7-4cc8-adff-9f4ae8c64d58', '25ec11f9-064b-472b-8671-f8f87855897e', 'OA_c', 'habilidad', 'Habilidades: Pensamiento temporal y espacial', 'Comparar aspectos sociales, económicos, culturales y políticos entre sociedades y civilizaciones del pasado y del presente para identificar continuidades y cambios.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('08604258-1afa-493e-a6d1-23aa8887f3aa', '25ec11f9-064b-472b-8671-f8f87855897e', 'OA_d', 'habilidad', 'Habilidades: Pensamiento temporal y espacial', 'Usar herramientas geográficas para ubicar y caracterizar elementos del espacio geográfico, como paisajes, población y recursos naturales.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('2c0f57d6-0788-47c6-86c2-9d677f89931a', '25ec11f9-064b-472b-8671-f8f87855897e', 'OA_e', 'habilidad', 'Habilidades: Pensamiento temporal y espacial', 'Orientarse en el espacio, utilizando categorías de ubicación absoluta (coordenadas geográficas) y relativa. Obtener información sobre el pasado y el presente a partir de diversas fuentes dadas (como entrevistas, narraciones, textos, medios audiovisuales, mapas, imágenes, gráficos, tablas y pictogramas, entre otros) y aplicar estrategias para registrar las ideas más relevantes.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('e82a4e75-2a40-4eaa-bf31-c92312906f1f', '25ec11f9-064b-472b-8671-f8f87855897e', 'OA_g', 'habilidad', 'Habilidades: Análisis y trabajo con fuentes', 'Formular y responder preguntas con relación al pasado, al presente o al entorno geográfico, para profundizar sobre temas de su interés en textos y fuentes diversas.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
