INSERT INTO curriculum_grades (id, subject_id, grado, label, total_objetivos) VALUES ('2635236c-08fc-4ff9-b82b-4710c08a137f', 'dcddbbf8-21ad-4c4f-8da1-8496fdf657b1', '4', '4° Básico', 19) ON CONFLICT (id) DO UPDATE SET subject_id = EXCLUDED.subject_id, grado = EXCLUDED.grado, label = EXCLUDED.label, total_objetivos = EXCLUDED.total_objetivos;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('ecd3c96b-634b-4018-b6fc-5a9fa0d513cc', '2635236c-08fc-4ff9-b82b-4710c08a137f', 'OA1', 'conocimiento', 'Historia', 'Describir la civilización maya, considerando ubicación geográfica, organización política, actividades económicas, formas de cultivo y alimentos, organización de la sociedad, roles y oficios de hombres y mujeres, religión y ritos, desarrollo de la astronomía y la matemática, sistemas de escritura, guerras y sacrificios humanos, construcciones, costumbres y vida cotidiana, entre otros.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('7236d2a3-1207-4d8b-9c88-212bcbab220b', '2635236c-08fc-4ff9-b82b-4710c08a137f', 'OA2', 'conocimiento', 'Historia', 'Describir la civilización azteca, considerando ubicación geográfica, organización política y extensión, la ciudad de Tenochtitlán, formas de cultivo y alimentos, religión y ritos, avances tecnológicos, organización de la sociedad, roles y oficios de hombres y mujeres, construcciones, costumbres y vida cotidiana, entre otros.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('f6fc529f-13a4-429a-adaa-597713890b2a', '2635236c-08fc-4ff9-b82b-4710c08a137f', 'OA3', 'conocimiento', 'Historia', 'Describir la civilización inca, considerando ubicación geográfica, organización política, sistema de caminos y correos, religión y ritos, avances tecnológicos, organización de la sociedad, roles y oficios de hombres y mujeres, formas de cultivo y alimentos, construcciones, costumbres y vida cotidiana, entre otros.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('c849d557-6e94-436a-ab57-d4e20f53de7e', '2635236c-08fc-4ff9-b82b-4710c08a137f', 'OA4', 'conocimiento', 'Historia', 'Analizar y comparar las principales características de las civilizaciones americanas (mayas, aztecas e incas).') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('cbab5875-f5c1-4bed-8996-23860eff7aad', '2635236c-08fc-4ff9-b82b-4710c08a137f', 'OA5', 'conocimiento', 'Historia', 'Investigar en diversas fuentes (imágenes, medios audiovisuales, TICs, gráficos, textos y otras) sobre algunos temas relacionados con el presente de los pueblos indígenas americanos; por ejemplo, el protagonismo que tienen hoy, la influencia de las civilizaciones maya, azteca e inca sobre la cultura y la sociedad de los países actuales situados donde ellos se desarrollaron, y su influencia en las comidas y en la lengua que empleamos en la actualidad, entre otros.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('bfce27f5-f883-4348-9f23-5ac1fdfbb00a', '2635236c-08fc-4ff9-b82b-4710c08a137f', 'OA6', 'conocimiento', 'Geografía', 'Ubicar lugares en un mapa, utilizando coordenadas geográficas como referencia (paralelos y meridianos).') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('aab077dd-87b4-4db2-a04f-e04a0e33c27f', '2635236c-08fc-4ff9-b82b-4710c08a137f', 'OA7', 'conocimiento', 'Geografía', 'Distinguir recursos naturales renovables y no renovables, reconocer el carácter limitado de los recursos naturales y la necesidad de cuidarlos, e identificar recursos presentes en objetos y bienes cotidianos.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('a95cbdd4-fa16-4d0f-9720-bcd3572f02fd', '2635236c-08fc-4ff9-b82b-4710c08a137f', 'OA8', 'conocimiento', 'Geografía', 'Describir distintos paisajes del continente americano, considerando climas, ríos, población, idiomas, países y grandes ciudades, entre otros, y utilizando vocabulario geográfico adecuado. los principales recursos naturales de América, considerando su distribución geográfica, su uso, y la importancia de cuidarlos en el marco de un desarrollo sostenible. la observación en imágenes, mapas y otras fuentes, paicon paisajes de América, distinguiendo distintas formas de ormación de la población a su ambiente natural. actores de la organización política y democrática de Chile, nistros, senadores, diputados y alcaldes, considerando las s que ejercen y cómo son nombrados o elegidos. ipales derechos en situaciones de la vida cotidiana, como cación, a contar con alimentación, vivienda, recreo y servidos, a expresarse, a ser protegido contra el abandono y la abajar antes de la edad apropiada, y dar ejemplos de cómo proteger esos derechos. ta honesta en la vida cotidiana, en los juegos y en el blando con la verdad, respetando las reglas de los juegos vitando la copia y el plagio y reconociendo sus errores y sus os. or todas las personas mediante acciones en su vida diaria, condiciones físicas, sociales, económicas, étnicas o culturamunidad, tomando parte en elecciones para una directiva o roles y funciones a cada cargo, y considerando la imporuna buena convivencia y una organización del curso que o escolar. , aplicando estrategias como determinar la causa del posibles soluciones, dialogar, buscar un punto de vista e otras, demostrando respeto y empatía por las para mejorar la convivencia en el curso y en la comunidad r activamente en un proyecto grupal que solucione un proad escolar; por ejemplo, reciclaje de la basura, exceso de de turnos, leer o entretener a alumnos más pequeños, etc. con fundamentos sobre temas de la asignatura u otros.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('ebcdf2ec-bf51-4da9-b2ce-5c8b384777ba', '2635236c-08fc-4ff9-b82b-4710c08a137f', 'OA_a', 'habilidad', 'Habilidades: Pensamiento crítico', 'Representar e interpretar secuencias cronológicas y acontecimientos del pasado iante líneas de tiempo, distinguiendo períodos.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('b98ad7a0-4e62-43c1-a5a6-af85349cbfaf', '2635236c-08fc-4ff9-b82b-4710c08a137f', 'OA_b', 'habilidad', 'Habilidades: Pensamiento crítico', 'Aplicar conceptos relacionados con el tiempo (años, décadas, siglos, períodos, hitos) en relación con la historia de Chile.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('15f9075e-8766-4b85-a993-d5e492623101', '2635236c-08fc-4ff9-b82b-4710c08a137f', 'OA_c', 'habilidad', 'Habilidades: Pensamiento crítico', 'Analizar elementos de continuidad y de cambio en procesos de la historia de Chile y entre un período histórico y otro, considerando aspectos sociales, políticos, culturales y económicos.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('ac2d83c5-8803-4c81-8e28-63d7f1a50367', '2635236c-08fc-4ff9-b82b-4710c08a137f', 'OA_d', 'habilidad', 'Habilidades: Pensamiento crítico', 'Usar herramientas geográficas para ubicar, caracterizar y relacionar elementos del espacio geográfico, como regiones, climas, paisajes, población, recursos y riesgos naturales.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('37ab1436-de1e-4540-953a-f2e4af1f08db', '2635236c-08fc-4ff9-b82b-4710c08a137f', 'OA_e', 'habilidad', 'Habilidades: Pensamiento crítico', 'Orientarse en el espacio, utilizando categorías de ubicación absoluta (coordenadas geográficas) y relativa.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('3de74ff5-d3e7-4ae9-8510-4fcad05a49bc', '2635236c-08fc-4ff9-b82b-4710c08a137f', 'OA_f', 'habilidad', 'Habilidades: Análisis y trabajo con fuentes', 'Obtener información sobre el pasado y el presente a partir de diversas fuentes marias y secundarias.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('440292a8-b74a-415e-b0bd-e4bcc27b6b51', '2635236c-08fc-4ff9-b82b-4710c08a137f', 'OA_g', 'habilidad', 'Habilidades: Análisis y trabajo con fuentes', 'Investigar sobre temas del nivel y aplicar distintas estrategias para registrar y organizar la información obtenida de una fuente sobre un tema (como organizadores gráficos, tablas, lista de ideas principales y esquemas, entre otros).') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('ba34faac-43ce-4ad1-b962-ba5e30fd5f95', '2635236c-08fc-4ff9-b82b-4710c08a137f', 'OA_h', 'habilidad', 'Habilidades: Pensamiento crítico', 'Formular y responder preguntas para profundizar sobre temas de su interés, en ación con el pasado, el presente o el entorno geográfico.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('5ec2d463-98e7-4219-884a-04f0625b476d', '2635236c-08fc-4ff9-b82b-4710c08a137f', 'OA_i', 'habilidad', 'Habilidades: Pensamiento crítico', 'Fundamentar opiniones respecto de temas estudiados en el nivel, utilizando fuentes, datos y evidencia.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('bc4cabb1-cde8-4543-8977-db1c469bd776', '2635236c-08fc-4ff9-b82b-4710c08a137f', 'OA_j', 'habilidad', 'Habilidades: Pensamiento crítico', 'Comparar distintos puntos de vista respecto de un mismo tema.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('72fe1cf8-cb69-45ad-970a-0c66f08d4f0d', '2635236c-08fc-4ff9-b82b-4710c08a137f', 'OA_k', 'habilidad', 'Habilidades: Pensamiento crítico', 'Identificar las causas de los procesos históricos estudiados y dar ejemplos que reflejen su carácter multicausal.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_grades (id, subject_id, grado, label, total_objetivos) VALUES ('504481ab-664d-43d9-8e8d-0cddb587dd1a', 'dcddbbf8-21ad-4c4f-8da1-8496fdf657b1', '5', '5° Básico', 20) ON CONFLICT (id) DO UPDATE SET subject_id = EXCLUDED.subject_id, grado = EXCLUDED.grado, label = EXCLUDED.label, total_objetivos = EXCLUDED.total_objetivos;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('dea09ffb-9215-49ba-8048-29dbe4f30c9d', '504481ab-664d-43d9-8e8d-0cddb587dd1a', 'OA1', 'conocimiento', 'Historia', 'Explicar los viajes de descubrimiento de Cristóbal Colón, de Hernando de Magallanes y de algún otro explorador, considerando sus objetivos, las rutas recorridas, los avances tecnológicos que facilitaron la navegación, las dificultades y los desafíos que enfrentaron las tripulaciones y el contexto europeo general en que se desarrollaron.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('bf7f80a0-5a8c-40cb-b908-f3772ce73d66', '504481ab-664d-43d9-8e8d-0cddb587dd1a', 'OA2', 'conocimiento', 'Historia', 'Describir el proceso de conquista de América y de Chile, incluyendo a los principales actores (Corona española, Iglesia católica y hombres y mujeres protagonistas, entre otros), algunas expediciones y conflictos bélicos, y la fundación de ciudades como expresión de la voluntad de los españoles de quedarse y expandirse, y reconocer en este proceso el surgimiento de una nueva sociedad.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('7872f615-ce05-4b0f-ba4d-bea7786f3116', '504481ab-664d-43d9-8e8d-0cddb587dd1a', 'OA3', 'conocimiento', 'Historia', 'Analizar el impacto y las consecuencias que tuvo el proceso de conquista para Europa y para América, considerando diversos ámbitos.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('9d87b15b-b754-4a7e-ac76-2dd40a88a208', '504481ab-664d-43d9-8e8d-0cddb587dd1a', 'OA4', 'conocimiento', 'Historia', 'Investigar sobre los efectos de la conquista sobre los pueblos indígenas americanos, utilizando fuentes dadas por el docente.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('f2d62825-dd10-4b63-b1f8-1eafe80f9891', '504481ab-664d-43d9-8e8d-0cddb587dd1a', 'OA5', 'conocimiento', 'Historia', 'Describir algunas dimensiones de la vida colonial en Chile, como organización de la sociedad y grupos sociales, oficios y actividades económicas, costumbres y vida cotidiana, arte y celebraciones.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('357f66dd-55ce-4a79-b94a-bc26b8e2e2d4', '504481ab-664d-43d9-8e8d-0cddb587dd1a', 'OA6', 'conocimiento', 'Historia', 'Explicar aspectos centrales de la Colonia, como la dependencia de las colonias americanas de la metrópoli, el rol de la Iglesia católica y el surgimiento de una sociedad mestiza.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('8ed2b018-6ecc-4125-83bb-2ec65f0bd37f', '504481ab-664d-43d9-8e8d-0cddb587dd1a', 'OA7', 'conocimiento', 'Historia', 'Explicar y dar ejemplos de las distintas formas en las que españoles y mapuches se relacionaron en el período colonial, considerando resistencia mapuche y guerra de Arauco, mestizaje, formas de trabajo (como encomienda y esclavitud), evangelización, vida fronteriza y sistema de parlamentos.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('3089a6e7-02c3-4707-b597-9c544fe275bf', '504481ab-664d-43d9-8e8d-0cddb587dd1a', 'OA8', 'conocimiento', 'Historia', 'Identificar, en su entorno o en fotografías, elementos del patrimonio colonial de Chile que siguen presentes hoy, como edificios, obras de arte y costumbres, entre otros.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('3313130c-f43f-42f2-a79e-722655a99434', '504481ab-664d-43d9-8e8d-0cddb587dd1a', 'OA9', 'conocimiento', 'Geografía', 'Caracterizar las grandes zonas de Chile y sus paisajes (Norte Grande, Norte Chico, Zona Central, Zona Sur y Zona Austral), considerando ubicación, clima (temperatura y precipitaciones), relieve, hidrografía, población y recursos naturales, entre otros. 10 Reconocer y ubicar en mapas recursos naturales significativos de Chile, como cobre, hierro, recursos marítimos y forestales, entre otros; diferenciar recursos renovables y no renovables y explicar la importancia de cuidarlos en el marco de un desarrollo sostenible. 11 Analizar y dar ejemplos de diversas maneras en las que el trabajo de las personas, sus ideas y proyectos potencian y dan valor a los recursos naturales (por ejemplo: tecnología de riego, elaboración de vinos, uso de madera en la construcción, nuevas formas de explotación sustentable). 12 Investigar, describir y ubicar los riesgos naturales que afectan a su localidad, como sismos, maremotos, inundaciones, derrumbes y volcanismo, e identificar formas en que la comunidad puede protegerse (construcciones antisísmicas, medidas de seguridad y evacuación en el hogar, en la escuela y en los distintos espacios públicos, entre otros). er que todas las personas son sujetos de derecho, que deben ser dos por los pares, la comunidad y el Estado, y que esos derechos no dependen de características individuales, como etnia, sexo, lugar de nacimiento u otras. 14 Reconocer que los derechos generan deberes y responsabilidades en las personas y en el Estado, lo que se manifiesta, por ejemplo, en que: úlas personas deben respetar los derechos de los demás útodas las personas deben respetar las leyes úel Estado debe asegurar que las personas puedan ejercer sus derechos (a la educación, a la protección de la salud, a la libertad de expresión, a la propiedad privada y a la igualdad ante la ley, entre otros) úel Estado debe asegurar los derechos de las personas a participar en la vida pública, como el derecho a formar organizaciones de participación social (fundaciones, juntas de vecinos, etc.), a participar en partidos políticos y el derecho a sufragio, entre otros beneficios que dependen del esfuerzo, el mérito persona (como las calificaciones, los premios compañerismo, el aprecio y el reconocimiento por razgo). con acciones en su vida diaria, como: sponsabilidad (ejemplos: respetar los acuerdos estoría de música y películas, evitar el plagio escolar, nas (ejemplos: no discriminar por condiciones les o étnicas, escuchar respetuosamente opiniones os y propiedad de los demás, etc.) ivencia (ejemplos: buscar soluciones pacíficas para r empatía con los demás, etc.) onio y el medioambiente (ejemplos: realizar camdado de nuestro patrimonio, usar la energía de tomando parte en elecciones para una directiva de nciones a cada cargo, y demostrando que entienden leva consigo el desempeño de un cargo y la imporue se estimen idóneas, para mantener una buena ión del curso que permita el trabajo escolar. proyecto que solucione un problema de la comuniemas como voluntariado, gasto excesivo de agua y y cuidado del medioambiente, entre otros, y ateresupuesto. rupo de personas puede organizarse para resolver ad de vida y la de otros y lograr metas comunes; oluntariado, empresas, agrupaciones y recolección icas. damentos sobre temas de la asignatura u otros. frente a un problema o proyecto y justificar su emas relevantes y de su interés en el país y el mun- , deporte, arte y música, entre otros) por medio de') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('a2fd76e1-f2fc-4718-9097-c48f39527376', '504481ab-664d-43d9-8e8d-0cddb587dd1a', 'OA_a', 'habilidad', 'Habilidades: Pensamiento crítico', 'Representar e interpretar secuencias cronológicas mediante líneas de tiempo simples y paralelas, e identificar períodos y acontecimientos simultáneos.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('6bce24b9-5068-4a4b-9587-7fe3f33a5fd9', '504481ab-664d-43d9-8e8d-0cddb587dd1a', 'OA_b', 'habilidad', 'Habilidades: Pensamiento temporal y espacial', 'Aplicar conceptos relacionados con el tiempo (años, décadas, siglos, períodos, hitos) y utilizarlos en relación con la historia de Chile.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('caac890f-19e6-407d-b6b8-fe1b39d7112f', '504481ab-664d-43d9-8e8d-0cddb587dd1a', 'OA_c', 'habilidad', 'Habilidades: Pensamiento temporal y espacial', 'Analizar elementos de continuidad y de cambio en procesos, entre períodos históricos y en relación con la actualidad, considerando aspectos sociales, políticos, culturales y económicos.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('4601c72e-dd82-4a41-b406-3a920cf1403f', '504481ab-664d-43d9-8e8d-0cddb587dd1a', 'OA_d', 'habilidad', 'Habilidades: Pensamiento temporal y espacial', 'Usar herramientas geográficas para ubicar, caracterizar y relacionar elementos del espacio geográfico, como regiones, climas, paisajes, población, recursos y riesgos naturales. mación sobre el pasado y el presente a partir de diversas rias y secundarias, identificando el contexto histórico e infiriendo la intención o la función original de estas fuentes.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('682cd3a2-d841-456b-9083-ef4bec33f190', '504481ab-664d-43d9-8e8d-0cddb587dd1a', 'OA_f', 'habilidad', 'Habilidades: Análisis y trabajo con fuentes', 'Investigar sobre temas del nivel y aplicar distintas estrategias para registrar y organizar la información obtenida de dos o más fuentes sobre un tema (como organizadores gráficos, tablas, lista de ideas principales y esquemas, entre otros).') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('ffa69d3c-f60d-4367-b35d-20e18fa50e8a', '504481ab-664d-43d9-8e8d-0cddb587dd1a', 'OA_g', 'habilidad', 'Habilidades: Análisis y trabajo con fuentes', 'Contrastar información a partir de dos fuentes históricas y/o geográficas distintas, por medio de preguntas dirigidas, y extraer conclusiones.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('49250163-8c4c-410e-a014-3ef4fe34cf5e', '504481ab-664d-43d9-8e8d-0cddb587dd1a', 'OA_h', 'habilidad', 'Habilidades: Pensamiento crítico', 'Formular y responder preguntas para profundizar sobre temas de su interés, con relación al pasado, al presente o al entorno geográfico.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('feecb947-8a77-4654-bb20-a0e38ac17a72', '504481ab-664d-43d9-8e8d-0cddb587dd1a', 'OA_i', 'habilidad', 'Habilidades: Pensamiento crítico', 'Fundamentar opiniones frente a temas estudiados en el nivel, utilizando fuentes, datos y evidencia.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('c7b2ef89-1051-4123-9444-6cd637dec01c', '504481ab-664d-43d9-8e8d-0cddb587dd1a', 'OA_j', 'habilidad', 'Habilidades: Pensamiento crítico', 'Comparar distintos puntos de vista respecto de un mismo tema.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('1223af7d-5549-4513-9985-3c051ff1b138', '504481ab-664d-43d9-8e8d-0cddb587dd1a', 'OA_k', 'habilidad', 'Habilidades: Pensamiento crítico', 'Evaluar posibles soluciones frente a un problema o proyecto y justificar su elección.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('bc69a5c3-16ce-4c99-bb22-ec3289a7bba8', '504481ab-664d-43d9-8e8d-0cddb587dd1a', 'OA_l', 'habilidad', 'Habilidades: Pensamiento crítico', 'Explicar las causas de un proceso histórico, reconociendo su carácter multicausal.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_grades (id, subject_id, grado, label, total_objetivos) VALUES ('078f214a-0575-4857-b67f-ab1ac8438358', 'dcddbbf8-21ad-4c4f-8da1-8496fdf657b1', '6', '6° Básico', 9) ON CONFLICT (id) DO UPDATE SET subject_id = EXCLUDED.subject_id, grado = EXCLUDED.grado, label = EXCLUDED.label, total_objetivos = EXCLUDED.total_objetivos;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('3860f3ad-2f64-425c-9948-8ec05d3a6856', '078f214a-0575-4857-b67f-ab1ac8438358', 'OA1', 'conocimiento', 'Historia', 'Explicar los múltiples antecedentes de la independencia de las colonias americanas y reconocer que la independencia de Chile se enmarca en un proceso continental.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('0d47a9e4-f756-4245-a564-3897cdaee0d2', '078f214a-0575-4857-b67f-ab1ac8438358', 'OA2', 'conocimiento', 'Historia', 'Explicar el desarrollo del proceso de independencia de Chile, considerando actores y bandos que se enfrentaron, hombres y mujeres destacados, avances y retrocesos de la causa patriota, y algunos acontecimientos significativos, como la celebración del cabildo abierto de 1810 y la formación de la Primera Junta Nacional de Gobierno, la elección del primer Congreso Nacional, las batallas de Rancagua, Chacabuco y Maipú, y la Declaración de la Independencia, entre otros.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('394aa37d-3690-473b-967e-89b517ef8e44', '078f214a-0575-4857-b67f-ab1ac8438358', 'OA3', 'conocimiento', 'Historia', 'Describir algunos hitos y procesos de la organización de la república, incluyendo las dificultades y los desafíos que implicó organizar en Chile una nueva forma de gobierno, el surgimiento de grupos con diferentes ideas políticas (conservadores y liberales), las características de la Constitución de 1833 y el impacto de las reformas realizadas por los liberales en la segunda mitad del siglo XIX.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('4ef5e57e-43f6-409d-8766-15f34f8dd5ee', '078f214a-0575-4857-b67f-ab1ac8438358', 'OA4', 'conocimiento', 'Historia', 'Investigar sobre algunos aspectos culturales del siglo XIX, como los avances en educación y la fundación de instituciones, el aporte de intelectuales y científicos nacionales (por ejemplo, Diego Barros Arana, Benjamín Vicuña Mackenna, José Victorino Lastarria) y extranjeros (por ejemplo, Andrés Bello, Claudio Gay, Charles Darwin y María Graham), las primeras mujeres en obtener títulos universitarios y el impacto en la sociedad de la llegada del ferrocarril y de otros avances tecnológicos, entre otros.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('01f9495a-7a4e-4d8d-847e-b06c08859487', '078f214a-0575-4857-b67f-ab1ac8438358', 'OA5', 'conocimiento', 'Historia', 'Describir cómo se conformó el territorio de Chile durante el siglo XIX, considerando colonizaciones europeas, la incorporación de Isla de Pascua, la ocupación de la Araucanía, la Guerra del Pacífico y diversos conflictos bélicos, entre otros factores.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('8eaf2063-ee8f-468b-84d2-e2c8f793ebd7', '078f214a-0575-4857-b67f-ab1ac8438358', 'OA6', 'conocimiento', 'Historia', 'Caracterizar los principales aspectos que definieron el período de riqueza aportada por la explotación del salitre, considerando la expansión económica y el inicio de la “cuestión social”.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('a546a453-277a-45a1-85ef-77911d43fd0c', '078f214a-0575-4857-b67f-ab1ac8438358', 'OA7', 'conocimiento', 'Historia', 'Explicar y dar ejemplos de la progresiva democratización de la sociedad durante el siglo XX, considerando el acceso creciente al voto, la participación de la mujer en la vida pública y el acceso a la educación y a la cultura, entre otros.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('5fb83abc-bcd8-4b25-8fb3-2f096c7ab69f', '078f214a-0575-4857-b67f-ab1ac8438358', 'OA8', 'conocimiento', 'Historia', 'Comparar diferentes visiones sobre el quiebre de la democracia en Chile, el régimen o dictadura militar y el proceso de recuperación de la democracia a fines del siglo XX, considerando los distintos actores, experiencias y puntos de vista, y el consenso actual con respecto al valor de la democracia.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('308af175-c8a4-4f9e-a065-d4fa3db25b93', '078f214a-0575-4857-b67f-ab1ac8438358', 'OA9', 'conocimiento', 'Historia', 'Explicar y dar ejemplos de aspectos que se mantienen y aspectos que han cambiado o se han desarrollado en la sociedad chilena a lo largo de su historia. icar elementos constitutivos del territorio nacional, considerando la localización de Chile en el mundo y su carácter tricontinental. 11 Caracterizar geográficamente las regiones político-administrativas del país, destacando los rasgos físicos (como clima, relieve, hidrografía y vegetación) y humanos (como volumen y distribución de la población y actividades económicas) que les dan unidad. 12 Comparar diversos ambientes naturales en Chile (desértico, altiplánico, costero, mediterráneo, andino, frío y lluvioso, patagónico y polar), considerando como criterios las oportunidades y las dificultades que presentan y cómo las personas las han aprovechado y superado para vivir y desarrollarse. 13 Explicar las principales características físicas, humanas y económicas de su región y de su localidad. 14 Explicar cómo han influido los desastres naturales en el desarrollo de Chile durante su historia reciente, dando ejemplos de nivel nacional y regional (sismos, volcanismo, sequía, inundaciones y derrumbes, entre otros). r algunos elementos fundamentales de la organización democrática de incluyendo: úla división de poderes del Estado úla representación mediante cargos de elección popular (concejales, alcaldes, diputados, senadores y Presidente) úla importancia de la participación ciudadana ón Política de Chile establece la organización políos derechos y las libertades de las personas, instauranrsonas tienen derechos que deben ser respetados y el Estado, lo que constituye la base para vivir en omo ejemplo algunos artículos de la Constitución y de los Derechos Humanos. eneran deberes y responsabilidades en las personas tante que 