INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('f9c7215d-846d-4e78-944d-e46e4bfa3ec7', '8e18dd37-248b-4a03-b1c2-ddd8f5f0d580', 'OA9', 'conocimiento', 'Números y Operaciones', 'Demostrar que comprenden la adición y la sustracción de números del 0 al 20 progresivamente, de 0 a 5, de 6 a 10, de 11 a 20 con dos sumandos: manera manual y/o usando software educativo 10 Demostrar que la adición y la sustracción son operaciones inversas, de manera concreta, pictórica y simbólica. rial concreto, pictórico y simbólico, de manera manual y/o por medio de software educativo. 12 Describir y registrar la igualdad y la desigualdad como equilibrio y desequilibrio, usando una balanza en forma concreta, pictórica y simbólica del 0 al 20, usando el símbolo igual (=). tos y personas, usando un lenguaje común (como derecha e izquierda). 14 Identificar en el entorno figuras 3D y figuras 2D y relacionarlas, usando material concreto. 15 Identificar y dibujar líneas rectas y curvas. cotidianos. 17 Usar un lenguaje cotidiano para secuenciar eventos en el tiempo: días de la semana, meses del año y algunas fechas significativas. 18 Identificar y comparar la longitud de objetos, usando palabras como largo y corto. 20 Construir, leer e interpretar pictogramas.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
