INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('73e43add-f81c-4b7b-bc5e-30cb60ea7e92', '73f1ff7d-8f4f-4956-a48a-c065b218f007', 'OA9', 'conocimiento', 'Números y Operaciones', 'Demostrar que comprende la adición y la sustracción en el ámbito del 0 al 100: úusando un lenguaje cotidiano y matemático para describir acciones desde su propia experiencia úresolviendo problemas con una variedad de representaciones concretas y pictóricas, de manera manual y/o usando software educativo úregistrando el proceso en forma simbólica úaplicando los resultados de las adiciones y las sustracciones de los números del 0 a 20 sin realizar cálculos úaplicando el algoritmo de la adición y la sustracción sin considerar reserva úcreando problemas matemáticos en contextos familiares y resolviéndolos 10 Demostrar que comprende la relación entre la adición y la sustracción al usar la “familia de operaciones” en cálculos aritméticos y la resolución de problemas 11 Demostrar que comprende la multiplicación: usando representaciones concretas y pictóricas ú expresando una multiplicación como una adición de sumandos iguales ú usando la distributividad como estrategia para construir las tablas del 2, del 5 y ú del 10 resolviendo problemas que involucren las tablas del 2, del 5 y del 10. ú ar, representar y continuar una variedad de patrones numéricos y completar elementos faltantes, de manera manual y/o usando software educativo. 13 Demostrar, explicar y registrar la igualdad y la desigualdad en forma concreta y pictórica del 0 al 20, usando el símbolo igual (=) y los símbolos no igual (>, <). resentar y describir la posición de objetos y personas con relación a sí mismos y a otros objetos y personas, incluyendo derecha e izquierda y usando material concreto y dibujos. 15 Describir, comparar y construir figuras 2D (triángulos, cuadrados, rectángulos y círculos) con material concreto. 16 Describir, comparar y construir figuras 3D (cubos, paralelepípedos, esferas y conos) con diversos materiales. ntificar días, semanas, meses y fechas en el calendario. 18 Leer horas y medias horas en relojes digitales, en el contexto de la resolución de problemas. 19 Determinar la longitud de objetos, usando unidades de medidas no estandarizadas y unidades estandarizadas (cm y m), en el contexto de la resolución de problemas. istrar datos para responder preguntas estadísticas sobre juegos dos, usando bloques y tablas de conteo y pictogramas. Registrar en tablas y gráficos de barra simple, resultados de juegos aleatorios con dados y monedas. 22 Construir, leer e interpretar pictogramas con escala y gráficos de barra simple.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
