INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('cea7a9aa-846e-481c-abf2-35af6703b74e', '53efd22e-b8db-4769-ae3e-fba84d893687', 'OA8', 'conocimiento', 'Números y Operaciones', 'Demostrar que comprenden las tablas de multiplicar hasta el 10 de manera progresiva: cálculos úrepresentando y explicando la división como repartición y agrupación en partes iguales, con material concreto y pictórico úcreando y resolviendo problemas en contextos que incluyan la repartición y la agrupación úexpresando la división como una sustracción repetida údescribiendo y aplicando la relación inversa entre la división y la multiplicación úaplicando los resultados de las tablas de multiplicación hasta 10 · 10, sin realizar cálculos cren las cuatro operaciones (no combinadas). pictórica, simbólica, de forma manual y/o con software educativo lo geométrico que represente un número desconocido, en forma pictórica y simbólica del 0 al 100. construyendo una figura 3D a partir de una red (plantilla) ú desplegando la figura 3D ú forma de sus caras y el número de aristas y vértices. identificando ejemplos de ángulos en el entorno ú estimando la medida de ángulos, usando como referente ángulos de 45º y de 90o ú 20 Leer y registrar el tiempo en horas, medias horas, cuartos de hora y minutos en relojes análogos y digitales. 21 Demostrar que comprenden el perímetro de una figura regular e irregular: midiendo y registrando el perímetro de figuras del entorno en el contexto de la ú resolución de problemas determinando el perímetro de un cuadrado y de un rectángulo ú 22 Demostrar que comprende la medición del peso (g y kg): comparando y ordenando dos o más objetos a partir de su peso de manera informal ú usando modelos para explicar la relación que existe entre gramos y kilogramos ú estimando el peso de objetos de uso cotidiano, usando referentes ú midiendo y registrando el peso de objetos en números y en fracciones de uso ú común, en el contexto de la resolución de problemas 24 Registrar y ordenar datos obtenidos de juegos aleatorios con dados y monedas, encontrando el menor, el mayor y estimando el punto medio entre ambos. 25 Construir, leer e interpretar pictogramas y gráficos de barra simple con escala, de acuerdo a información recolectada o dada. 26 Representar datos usando diagramas de puntos.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
