INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('00fc711b-96d7-44aa-b2eb-04006473a851', 'c7876be3-6a22-4e6a-ae21-2dd72aaf9b19', 'OA6', 'conocimiento', 'Números y Operaciones', 'Resolver problemas rutinarios y no rutinarios que involucren las cuatro operaciones y combinaciones de ellas: 10.000 úrepresentándolas de manera concreta, pictórica y simbólica úcreando grupos de fracciones equivalentes –simplificando y amplificando– de manera concreta, pictórica y simbólica, de forma manual y/o con software educativo úcomparando fracciones propias con igual y distinto denominador de manera concreta, pictórica y simbólica dores 2, 3, 4, 5, 6, 8, 10, 12 y los números mixtos asociados: úusando material concreto y pictórico para representarlas, de manera manual y/o con software educativo úidentificando y determinando equivalencias entre fracciones impropias y números mixtos úrepresentando estas fracciones y estos números mixtos en la recta numérica nores o iguales a 12: 10. hasta la milésima. de fracciones propias o decimales hasta la milésima. adiciones y sustracciones, en forma pictórica y simbólica. coordenadas en números naturales. que son paralelos ú que se intersectan ú que son perpendiculares ú 18 Demostrar que comprenden el concepto de congruencia, usando la traslación, la reflexión y la rotación en cuadrículas y mediante software geométrico. resolución de problemas. 20 Realizar transformaciones entre unidades de medidas de longitud: km a m, m a cm, cm a mm y viceversa, de manera manual y/o usando software educativo. 21 Diseñar y construir diferentes rectángulos, dados el perímetro, el área o ambos, y sacar conclusiones. 22 Calcular áreas de triángulos, de paralelogramos y de trapecios, y estimar áreas de figuras irregulares, aplicando las siguientes estrategias: mento aleatorio, empleando los términos seguro – posible - poco posible - imposible. 25 Comparar probabilidades de distintos eventos sin calcularlas. 26 Leer, interpretar y completar tablas, gráficos de barra simple y gráficos de línea y comunicar sus conclusiones. 27 Utilizar diagramas de tallo y hojas para representar datos provenientes de muestras aleatorias.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
