INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('11f72ebe-8fed-4365-980d-cb9428a8e0c6', '8c8f2924-a0a6-45ff-8455-2280a3ee9042', 'OA8', 'conocimiento', 'Números y Operaciones', 'Resolver problemas rutinarios y no rutinarios que involucren adiciones y sustracciones de fracciones propias, impropias, números mixtos o decimales hasta la milésima.') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
INSERT INTO curriculum_objectives (id, grade_id, codigo, tipo, eje, descripcion) VALUES ('ec6a2eb7-f82b-4b46-af5a-81ce0cf12750', '8c8f2924-a0a6-45ff-8455-2280a3ee9042', 'OA9', 'conocimiento', 'Patrones y Álgebra', 'Demostrar que comprenden la relación entre los valores de una tabla y aplicarla en la ución de problemas sencillos: 10 Representar generalizaciones de relaciones entre números naturales, usando expresiones con letras y ecuaciones. 11 Resolver ecuaciones de primer grado con una incógnita, utilizando estrategias como: úusar una balanza úusar la descomposición y la correspondencia 1 a 1 entre los términos en cada lado de la ecuación y aplicando procedimientos formales de resolución. con instrumentos geométricos o software geométrico. 13 Demostrar que comprenden el concepto de área de una superficie en cubos y paralelepípedos, calculando el área de sus redes (plantillas) asociadas. 14 Realizar teselados de figuras 2D, usando traslaciones, reflexiones y rotaciones. 15 Construir ángulos agudos, obtusos, rectos, extendidos y completos con instrumentos geométricos o software geométrico. 16 Identificar los ángulos que se forman entre dos rectas que se cortan (pares de ángulos opuestos por el vértice y pares de ángulos complementarios). 17 Demostrar de manera concreta, pictórica y simbólica que la suma de los ángulos interiores de un triángulo es 180º y de un cuadrilátero es 360o. 19 Calcular el volumen de cubos y paralelepípedos, expresando el resultado en cm3, m3 y mm3. 20 Estimar y medir ángulos, usando el transportador y expresando las mediciones en grados. 21 Calcular ángulos en rectas paralelas cortadas por una transversal y en triángulos. 23 Conjeturar acerca de la tendencia de resultados obtenidos en repeticiones de un mismo experimento con dados, monedas u otros, de manera manual y/o usando software educativo. 24 Leer e interpretar gráficos de barra doble y circulares y comunicar sus conclusiones. Diagrama que permite exhibir rápidamente datos sobre una recta Ejemplo: Temperaturas máximas en el mes de octubre') ON CONFLICT (id) DO UPDATE SET grade_id = EXCLUDED.grade_id, codigo = EXCLUDED.codigo, tipo = EXCLUDED.tipo, eje = EXCLUDED.eje, descripcion = EXCLUDED.descripcion;
